{
  "name": "Lumina Design AI",
  "description": "An interactive AI interior design consultant. Upload your room, explore styles, and refine details with a smart chat assistant."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface DesignStyle {
  id: string;
  name: string;
  description: string;
  image: string; // Placeholder or thumbnail
}

export enum MessageRole {
  USER = 'user',
  MODEL = 'model',
  SYSTEM = 'system'
}

export interface ChatMessage {
  id: string;
  role: MessageRole;
  text: string;
  timestamp: number;
  isError?: boolean;
  groundingLinks?: GroundingLink[];
}

export interface GroundingLink {
  title: string;
  url: string;
}

export interface GeneratedImage {
  id: string;
  url: string; // Base64 data URI
  prompt: string;
  styleName: string;
}

export interface AppState {
  originalImage: string | null;
  generatedImages: GeneratedImage[];
  selectedImageId: string | null;
  isGenerating: boolean;
  activeStyle: string | null;
}

import { DesignStyle } from './types';

export const DESIGN_STYLES: DesignStyle[] = [
  {
    id: 'modern',
    name: 'Modern',
    description: 'Clean lines, minimalism, and natural light.',
    image: 'https://picsum.photos/id/1/200/200',
  },
  {
    id: 'scandinavian',
    name: 'Scandinavian',
    description: 'Functional, simple, warm woods, and neutral colors.',
    image: 'https://picsum.photos/id/2/200/200',
  },
  {
    id: 'mid-century',
    name: 'Mid-Century',
    description: 'Retro organic aesthetic from the 1950s.',
    image: 'https://picsum.photos/id/3/200/200',
  },
  {
    id: 'bohemian',
    name: 'Bohemian',
    description: 'Eclectic, colorful, layered patterns and plants.',
    image: 'https://picsum.photos/id/4/200/200',
  },
  {
    id: 'industrial',
    name: 'Industrial',
    description: 'Raw materials, exposed pipes, brick, and metal.',
    image: 'https://picsum.photos/id/5/200/200',
  },
];

export const INITIAL_CHAT_MESSAGE = "Hi! I'm your AI Design Consultant. Upload a photo of your room, pick a style, or tell me how you want to transform your space!";

import { GoogleGenAI, Type, FunctionDeclaration, Tool } from "@google/genai";
import { ChatMessage, MessageRole, GroundingLink } from '../types';

// Initialize Gemini Client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// --- Image Generation Service ---

/**
 * Generates or edits a room design using Gemini 2.5 Flash Image.
 * It takes the original image and a prompt describing the desired outcome.
 */
export const generateRoomDesign = async (
  imageBase64: string,
  prompt: string
): Promise<string> => {
  try {
    // Strip header if present (e.g., "data:image/jpeg;base64,")
    const cleanBase64 = imageBase64.split(',')[1] || imageBase64;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: 'image/jpeg', // Assuming JPEG for simplicity, can detect from input
              data: cleanBase64
            }
          },
          {
            text: `Reimagine this room. ${prompt}. Maintain the structural layout but apply the requested style and furniture changes. output high quality photorealistic image.`
          }
        ]
      },
      // Using gemini-2.5-flash-image (nano banana) usually outputs text or images depending on request. 
      // We expect an image in the response parts.
    });

    // Extract image from response
    // The response might contain text and/or images. We look for inlineData.
    if (response.candidates && response.candidates[0]?.content?.parts) {
        for (const part of response.candidates[0].content.parts) {
            if (part.inlineData && part.inlineData.data) {
                return `data:image/jpeg;base64,${part.inlineData.data}`;
            }
        }
    }

    throw new Error("No image generated.");
  } catch (error) {
    console.error("Image generation failed:", error);
    throw error;
  }
};


// --- Chat Service ---

// Function Declaration for the Chat Model to trigger design updates
const updateDesignFunction: FunctionDeclaration = {
  name: 'update_room_design',
  description: 'Updates the visual design of the room based on the user\'s description. Use this when the user asks to change colors, furniture, style, or specific visual elements.',
  parameters: {
    type: Type.OBJECT,
    properties: {
      visual_description: {
        type: Type.STRING,
        description: 'A detailed visual description of how the room should look. E.g., "A modern living room with a blue rug and white sofa".',
      },
    },
    required: ['visual_description'],
  },
};

const searchTool: Tool = {
  googleSearch: {}
};

const functionTool: Tool = {
  functionDeclarations: [updateDesignFunction]
};

/**
 * Sends a message to the design consultant (Gemini 3 Pro).
 * Supports search grounding and function calling for design updates.
 */
export const sendChatMessage = async (
  history: ChatMessage[],
  newMessage: string,
  onDesignUpdate: (description: string) => Promise<void>
): Promise<ChatMessage> => {

  // Format history for the API
  const contents = history.map(msg => ({
    role: msg.role === MessageRole.USER ? 'user' : 'model',
    parts: [{ text: msg.text }]
  }));

  // Add the new message
  contents.push({
    role: 'user',
    parts: [{ text: newMessage }]
  });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: contents,
      config: {
        systemInstruction: "You are an expert Interior Design Consultant. Help users redesign their rooms. If they ask for specific products or shopping advice, use Google Search. If they ask to change the look of the room (e.g., 'make the walls blue', 'switch to industrial style'), use the update_room_design function. Be concise, helpful, and enthusiastic.",
        tools: [searchTool, functionTool],
      }
    });

    const candidate = response.candidates?.[0];

    // Check for Function Calls
    const functionCalls = candidate?.content?.parts?.filter(p => p.functionCall).map(p => p.functionCall);

    let botText = "";

    if (functionCalls && functionCalls.length > 0) {
      for (const call of functionCalls) {
        if (call && call.name === 'update_room_design') {
          // Trigger the callback provided by the UI
          const args = call.args as any;
          botText += `(Updating design: "${args.visual_description}")... `;
          await onDesignUpdate(args.visual_description);
        }
      }
      // If the model only called a function, it might not have much text. 
      // We can append a confirmation if needed, or rely on the text part if present.
    }

    // Extract text response
    const textPart = candidate?.content?.parts?.find(p => p.text);
    if (textPart?.text) {
      botText += textPart.text;
    } else if (!botText) {
      botText = "I've updated the design for you!";
    }

    // Extract Grounding Metadata (Search results)
    const groundingLinks: GroundingLink[] = [];
    const chunks = candidate?.groundingMetadata?.groundingChunks;
    if (chunks) {
      chunks.forEach((chunk: any) => {
        if (chunk.web?.uri && chunk.web?.title) {
          groundingLinks.push({
            title: chunk.web.title,
            url: chunk.web.uri
          });
        }
      });
    }

    return {
      id: Date.now().toString(),
      role: MessageRole.MODEL,
      text: botText,
      timestamp: Date.now(),
      groundingLinks: groundingLinks.length > 0 ? groundingLinks : undefined
    };

  } catch (error) {
    console.error("Chat error:", error);
    return {
      id: Date.now().toString(),
      role: MessageRole.MODEL,
      text: "Sorry, I'm having trouble connecting to my design brain right now. Please try again.",
      timestamp: Date.now(),
      isError: true
    };
  }
};

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { ArrowRightLeft } from 'lucide-react';

interface ComparisonSliderProps {
  beforeImage: string;
  afterImage: string;
}

const ComparisonSlider: React.FC<ComparisonSliderProps> = ({ beforeImage, afterImage }) => {
  const [sliderPosition, setSliderPosition] = useState(50);
  const containerRef = useRef<HTMLDivElement>(null);
  const isDragging = useRef(false);

  const handleMove = useCallback((clientX: number) => {
    if (containerRef.current) {
      const rect = containerRef.current.getBoundingClientRect();
      const x = Math.max(0, Math.min(clientX - rect.left, rect.width));
      const percentage = (x / rect.width) * 100;
      setSliderPosition(percentage);
    }
  }, []);

  const handleMouseDown = () => {
    isDragging.current = true;
  };

  const handleTouchStart = () => {
    isDragging.current = true;
  };

  useEffect(() => {
    const handleMouseUp = () => {
      isDragging.current = false;
    };

    const handleMouseMove = (e: MouseEvent) => {
      if (isDragging.current) {
        handleMove(e.clientX);
      }
    };

    const handleTouchMove = (e: TouchEvent) => {
      if (isDragging.current) {
        handleMove(e.touches[0].clientX);
      }
    };

    window.addEventListener('mouseup', handleMouseUp);
    window.addEventListener('mousemove', handleMouseMove);
    window.addEventListener('touchend', handleMouseUp);
    window.addEventListener('touchmove', handleTouchMove);

    return () => {
      window.removeEventListener('mouseup', handleMouseUp);
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('touchend', handleMouseUp);
      window.removeEventListener('touchmove', handleTouchMove);
    };
  }, [handleMove]);

  return (
    <div 
      ref={containerRef}
      className="relative w-full h-full overflow-hidden select-none group cursor-ew-resize bg-gray-100"
    >
      {/* Background Image (After - Full Width) */}
      <img
        src={afterImage}
        alt="After"
        className="absolute top-0 left-0 w-full h-full object-cover"
      />

      {/* Foreground Image (Before - Clipped) */}
      <div
        className="absolute top-0 left-0 h-full overflow-hidden border-r-2 border-white/50 bg-gray-200"
        style={{ width: `${sliderPosition}%` }}
      >
        <img
          src={beforeImage}
          alt="Before"
          className="absolute top-0 left-0 max-w-none h-full object-cover"
          style={{ width: containerRef.current ? containerRef.current.offsetWidth : '100%' }}
        />
      </div>

      {/* Slider Handle */}
      <div
        className="absolute top-0 bottom-0 w-1 bg-white cursor-ew-resize shadow-[0_0_10px_rgba(0,0,0,0.5)]"
        style={{ left: `${sliderPosition}%` }}
        onMouseDown={handleMouseDown}
        onTouchStart={handleTouchStart}
      >
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-10 h-10 bg-white rounded-full flex items-center justify-center shadow-lg text-brand-600 hover:scale-110 transition-transform">
          <ArrowRightLeft size={20} />
        </div>
      </div>

      {/* Labels */}
      <div className="absolute top-4 left-4 bg-black/50 text-white px-3 py-1 rounded-full text-sm backdrop-blur-sm pointer-events-none">
        Original
      </div>
      <div className="absolute top-4 right-4 bg-brand-600/80 text-white px-3 py-1 rounded-full text-sm backdrop-blur-sm pointer-events-none">
        Redesigned
      </div>
    </div>
  );
};

export default ComparisonSlider;

import React, { useState, useRef, useEffect } from 'react';
import { Send, Loader2, ShoppingBag, ExternalLink } from 'lucide-react';
import { ChatMessage, MessageRole } from '../types';

interface ChatInterfaceProps {
  messages: ChatMessage[];
  onSendMessage: (text: string) => void;
  isTyping: boolean;
}

const ChatInterface: React.FC<ChatInterfaceProps> = ({ messages, onSendMessage, isTyping }) => {
  const [inputText, setInputText] = useState('');
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isTyping]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (inputText.trim()) {
      onSendMessage(inputText);
      setInputText('');
    }
  };

  return (
    <div className="flex flex-col h-full bg-white border-l border-slate-200 shadow-xl">
      <div className="p-4 border-b border-slate-100 bg-slate-50/50 backdrop-blur-sm">
        <h2 className="font-semibold text-slate-800 flex items-center gap-2">
          <span className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></span>
          Design Assistant
        </h2>
        <p className="text-xs text-slate-500">Powered by Gemini 3 Pro</p>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-4 scrollbar-hide">
        {messages.map((msg) => (
          <div
            key={msg.id}
            className={`flex flex-col ${
              msg.role === MessageRole.USER ? 'items-end' : 'items-start'
            }`}
          >
            <div
              className={`max-w-[85%] px-4 py-3 rounded-2xl text-sm leading-relaxed ${
                msg.role === MessageRole.USER
                  ? 'bg-brand-600 text-white rounded-br-none'
                  : 'bg-slate-100 text-slate-800 rounded-bl-none border border-slate-200'
              }`}
            >
              {msg.text}
            </div>

            {msg.groundingLinks && msg.groundingLinks.length > 0 && (
              <div className="mt-2 ml-1 flex flex-wrap gap-2 max-w-[85%]">
                {msg.groundingLinks.map((link, idx) => (
                  <a
                    key={idx}
                    href={link.url}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="flex items-center gap-1.5 text-xs bg-white border border-slate-200 text-brand-600 px-3 py-1.5 rounded-full hover:bg-slate-50 transition-colors shadow-sm"
                  >
                    <ShoppingBag size={12} />
                    <span className="truncate max-w-[150px]">{link.title}</span>
                    <ExternalLink size={10} className="ml-0.5 opacity-50" />
                  </a>
                ))}
              </div>
            )}

            <span className="text-[10px] text-slate-400 mt-1 px-1">
              {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
            </span>
          </div>
        ))}

        {isTyping && (
          <div className="flex items-start">
            <div className="bg-slate-100 rounded-2xl rounded-bl-none px-4 py-3 flex items-center gap-1.5">
              <span className="w-1.5 h-1.5 bg-slate-400 rounded-full animate-bounce"></span>
              <span className="w-1.5 h-1.5 bg-slate-400 rounded-full animate-bounce [animation-delay:0.1s]"></span>
              <span className="w-1.5 h-1.5 bg-slate-400 rounded-full animate-bounce [animation-delay:0.2s]"></span>
            </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      <form onSubmit={handleSubmit} className="p-4 border-t border-slate-100 bg-white">
        <div className="relative flex items-center">
          <input
            type="text"
            value={inputText}
            onChange={(e) => setInputText(e.target.value)}
            placeholder="Ask to change colors, style, or find items..."
            className="w-full bg-slate-50 border border-slate-200 text-slate-900 text-sm rounded-full pl-4 pr-12 py-3 focus:outline-none focus:ring-2 focus:ring-brand-500 focus:border-transparent transition-all"
            disabled={isTyping}
          />
          <button
            type="submit"
            disabled={!inputText.trim() || isTyping}
            className="absolute right-2 p-2 bg-brand-600 text-white rounded-full disabled:opacity-50 disabled:cursor-not-allowed hover:bg-brand-700 transition-colors shadow-md"
          >
            {isTyping ? <Loader2 size={16} className="animate-spin" /> : <Send size={16} />}
          </button>
        </div>
      </form>
    </div>
  );
};

export default ChatInterface;

import React, { useState, useEffect, useCallback } from 'react';
import { Upload, Image as ImageIcon, Wand2, Download, AlertCircle } from 'lucide-react';
import { generateRoomDesign, sendChatMessage } from './services/geminiService';
import { AppState, ChatMessage, GeneratedImage, MessageRole } from './types';
import { DESIGN_STYLES, INITIAL_CHAT_MESSAGE } from './constants';
import ComparisonSlider from './components/ComparisonSlider';
import ChatInterface from './components/ChatInterface';

const App: React.FC = () => {
  // --- State ---
  const [state, setState] = useState<AppState>({
    originalImage: null,
    generatedImages: [],
    selectedImageId: null,
    isGenerating: false,
    activeStyle: null,
  });

  const [chatHistory, setChatHistory] = useState<ChatMessage[]>([
    {
      id: 'init',
      role: MessageRole.MODEL,
      text: INITIAL_CHAT_MESSAGE,
      timestamp: Date.now(),
    },
  ]);
  const [isChatTyping, setIsChatTyping] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // --- Handlers ---

  // Handle Image Upload
  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      if (file.size > 10 * 1024 * 1024) { // 10MB limit
          setError("File too large. Please upload an image under 10MB.");
          return;
      }

      const reader = new FileReader();
      reader.onloadend = () => {
        setState((prev) => ({
          ...prev,
          originalImage: reader.result as string,
          generatedImages: [], // Clear previous results
          selectedImageId: null,
          activeStyle: null
        }));
        setError(null);

        // Add a system message to chat
        const newMsg: ChatMessage = {
            id: Date.now().toString(),
            role: MessageRole.MODEL,
            text: "Great photo! Choose a style from the carousel above, or describe how you want to change it.",
            timestamp: Date.now()
        };
        setChatHistory(prev => [...prev, newMsg]);
      };
      reader.readAsDataURL(file);
    }
  };

  // Generate Image from Style or Chat
  const handleGenerate = useCallback(async (prompt: string, styleId?: string) => {
    if (!state.originalImage) return;

    setState((prev) => ({ ...prev, isGenerating: true, activeStyle: styleId || null }));
    setError(null);

    try {
      const generatedImageBase64 = await generateRoomDesign(state.originalImage, prompt);

      const newImage: GeneratedImage = {
        id: Date.now().toString(),
        url: generatedImageBase64,
        prompt: prompt,
        styleName: styleId ? DESIGN_STYLES.find(s => s.id === styleId)?.name || 'Custom' : 'Custom'
      };

      setState((prev) => ({
        ...prev,
        generatedImages: [...prev.generatedImages, newImage],
        selectedImageId: newImage.id,
        isGenerating: false,
      }));
    } catch (err) {
      console.error(err);
      setError("Failed to generate design. Please try again.");
      setState((prev) => ({ ...prev, isGenerating: false, activeStyle: null }));
    }
  }, [state.originalImage]);

  // Handle Chat Message
  const handleSendMessage = async (text: string) => {
    // Add User Message
    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: MessageRole.USER,
      text: text,
      timestamp: Date.now(),
    };
    setChatHistory((prev) => [...prev, userMsg]);
    setIsChatTyping(true);

    // Call Gemini Chat
    // Note: We pass a callback for "Design Updates" that the model can trigger
    const onDesignUpdate = async (description: string) => {
        if (!state.originalImage) {
            setError("Please upload an image first.");
            return;
        }
        await handleGenerate(description);
    };

    const responseMsg = await sendChatMessage([...chatHistory, userMsg], text, onDesignUpdate);

    setChatHistory((prev) => [...prev, responseMsg]);
    setIsChatTyping(false);
  };

  // Derived State
  const activeImage = state.selectedImageId 
    ? state.generatedImages.find(img => img.id === state.selectedImageId)?.url 
    : null;

  return (
    <div className="flex flex-col h-screen overflow-hidden bg-slate-50">

      {/* --- Header --- */}
      <header className="flex-none h-16 bg-white border-b border-slate-200 flex items-center justify-between px-6 z-20 shadow-sm">
        <div className="flex items-center gap-2">
          <div className="bg-brand-600 p-2 rounded-lg text-white">
            <Wand2 size={20} />
          </div>
          <h1 className="text-xl font-bold text-slate-800 tracking-tight">Lumina <span className="text-brand-600">Design AI</span></h1>
        </div>
        <div className="flex items-center gap-4">
             {state.originalImage && (
              <button 
                onClick={() => {
                   setState(prev => ({...prev, originalImage: null, generatedImages: [], selectedImageId: null}))
                }}
                className="text-sm font-medium text-slate-500 hover:text-red-500 transition-colors"
              >
                Reset
              </button>
             )}
             <a href="https://github.com" target="_blank" rel="noreferrer" className="text-slate-400 hover:text-slate-800 transition-colors">
                <span className="text-xs font-semibold border border-slate-200 px-2 py-1 rounded-md">V1.0</span>
             </a>
        </div>
      </header>

      {/* --- Main Content --- */}
      <main className="flex-1 flex flex-col md:flex-row overflow-hidden relative">

        {/* --- Left / Top: Visualizer --- */}
        <div className="flex-1 flex flex-col min-w-0 bg-slate-100 relative">

          {/* Style Carousel (Overlay or Top Bar) */}
          {state.originalImage && (
            <div className="flex-none h-24 bg-white/80 backdrop-blur-md border-b border-white/50 flex items-center px-4 gap-3 overflow-x-auto scrollbar-hide z-10 shadow-sm">
               {DESIGN_STYLES.map((style) => (
                 <button
                    key={style.id}
                    onClick={() => handleGenerate(`Apply ${style.name} interior design style`, style.id)}
                    disabled={state.isGenerating}
                    className={`flex-none group relative rounded-xl overflow-hidden w-32 h-16 transition-all transform hover:scale-105 ${state.activeStyle === style.id ? 'ring-2 ring-brand-500 scale-105' : 'opacity-80 hover:opacity-100'}`}
                 >
                    <img src={style.image} alt={style.name} className="w-full h-full object-cover" />
                    <div className="absolute inset-0 bg-black/40 flex items-center justify-center">
                       <span className="text-white text-xs font-bold shadow-sm">{style.name}</span>
                    </div>
                    {state.isGenerating && state.activeStyle === style.id && (
                        <div className="absolute inset-0 bg-black/60 flex items-center justify-center">
                            <Loader size="small" />
                        </div>
                    )}
                 </button>
               ))}
            </div>
          )}

          {/* Visualizer Area */}
          <div className="flex-1 relative flex items-center justify-center p-4 md:p-8 overflow-hidden">

             {!state.originalImage ? (
                // Upload State
                <div className="w-full max-w-md bg-white rounded-3xl border-2 border-dashed border-slate-300 p-12 flex flex-col items-center justify-center text-center hover:border-brand-400 transition-colors group cursor-pointer relative">
                    <input 
                      type="file" 
                      accept="image/*" 
                      onChange={handleFileUpload} 
                      className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                    />
                    <div className="w-20 h-20 bg-brand-50 rounded-full flex items-center justify-center mb-6 group-hover:bg-brand-100 transition-colors">
                      <ImageIcon className="text-brand-500" size={32} />
                    </div>
                    <h3 className="text-xl font-bold text-slate-800 mb-2">Upload your room</h3>
                    <p className="text-slate-500 text-sm mb-6">Drag & drop or click to upload a photo of your space to start the transformation.</p>
                    <button className="bg-brand-600 text-white px-6 py-2 rounded-full font-medium shadow-lg shadow-brand-200 group-hover:shadow-brand-300 transition-all flex items-center gap-2">
                        <Upload size={16} /> Upload Photo
                    </button>
                </div>
             ) : (
                // Comparison State
                <div className="relative w-full h-full max-w-5xl bg-white rounded-2xl shadow-2xl overflow-hidden border border-slate-200">
                   {state.isGenerating && (
                     <div className="absolute inset-0 z-30 bg-black/30 backdrop-blur-sm flex flex-col items-center justify-center text-white">
                        <Loader />
                        <p className="mt-4 font-medium animate-pulse">Designing your space...</p>
                     </div>
                   )}

                   {activeImage ? (
                     <ComparisonSlider 
                       beforeImage={state.originalImage} 
                       afterImage={activeImage} 
                     />
                   ) : (
                     <img src={state.originalImage} alt="Original" className="w-full h-full object-contain bg-slate-100" />
                   )}

                   {/* Download Action */}
                   {activeImage && (
                     <a 
                       href={activeImage} 
                       download="lumina-design.jpg"
