import { generateRoomDesign, sendChatMessage } from './services/geminiService';
import { AppState, ChatMessage, GeneratedImage, MessageRole } from './types';
import { DESIGN_STYLES, INITIAL_CHAT_MESSAGE } from './constants';
import ComparisonSlider from './components/ComparisonSlider';
import ChatInterface from './components/ChatInterface';

const App: React.FC = () => {
  // --- State ---
  const [state, setState] = useState<AppState>({
    originalImage: null,
    generatedImages: [],
    selectedImageId: null,
    isGenerating: false,
    activeStyle: null,
  });

  const [chatHistory, setChatHistory] = useState<ChatMessage[]>([
    {
      id: 'init',
      role: MessageRole.MODEL,
      text: INITIAL_CHAT_MESSAGE,
      timestamp: Date.now(),
    },
  ]);
  const [isChatTyping, setIsChatTyping] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // --- Handlers ---

  // Handle Image Upload
  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      if (file.size > 10 * 1024 * 1024) { // 10MB limit
          setError("File too large. Please upload an image under 10MB.");
          return;
      }

      const reader = new FileReader();
      reader.onloadend = () => {
        setState((prev) => ({
          ...prev,
          originalImage: reader.result as string,
          generatedImages: [], // Clear previous results
          selectedImageId: null,
          activeStyle: null
        }));
        setError(null);

        // Add a system message to chat
        const newMsg: ChatMessage = {
            id: Date.now().toString(),
            role: MessageRole.MODEL,
            text: "Great photo! Choose a style from the carousel above, or describe how you want to change it.",
            timestamp: Date.now()
        };
        setChatHistory(prev => [...prev, newMsg]);
      };
      reader.readAsDataURL(file);
    }
  };

  // Generate Image from Style or Chat
  const handleGenerate = useCallback(async (prompt: string, styleId?: string) => {
    if (!state.originalImage) return;

    setState((prev) => ({ ...prev, isGenerating: true, activeStyle: styleId || null }));
    setError(null);

    try {
      const generatedImageBase64 = await generateRoomDesign(state.originalImage, prompt);

      const newImage: GeneratedImage = {
        id: Date.now().toString(),
        url: generatedImageBase64,
        prompt: prompt,
        styleName: styleId ? DESIGN_STYLES.find(s => s.id === styleId)?.name || 'Custom' : 'Custom'
      };

      setState((prev) => ({
        ...prev,
        generatedImages: [...prev.generatedImages, newImage],
        selectedImageId: newImage.id,
        isGenerating: false,
      }));
    } catch (err) {
      console.error(err);
      setError("Failed to generate design. Please try again.");
      setState((prev) => ({ ...prev, isGenerating: false, activeStyle: null }));
    }
  }, [state.originalImage]);

  // Handle Chat Message
  const handleSendMessage = async (text: string) => {
    // Add User Message
    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: MessageRole.USER,
      text: text,
      timestamp: Date.now(),
    };
    setChatHistory((prev) => [...prev, userMsg]);
    setIsChatTyping(true);

    // Call Gemini Chat
    // Note: We pass a callback for "Design Updates" that the model can trigger
    const onDesignUpdate = async (description: string) => {
        if (!state.originalImage) {
            setError("Please upload an image first.");
            return;
        }
        await handleGenerate(description);
    };

    const responseMsg = await sendChatMessage([...chatHistory, userMsg], text, onDesignUpdate);

    setChatHistory((prev) => [...prev, responseMsg]);
    setIsChatTyping(false);
  };

  // Derived State
  const activeImage = state.selectedImageId 
    ? state.generatedImages.find(img => img.id === state.selectedImageId)?.url 
    : null;

  return (
    <div className="flex flex-col h-screen overflow-hidden bg-slate-50">

      {/* --- Header --- */}
      <header className="flex-none h-16 bg-white border-b border-slate-200 flex items-center justify-between px-6 z-20 shadow-sm">
        <div className="flex items-center gap-2">
          <div className="bg-brand-600 p-2 rounded-lg text-white">
            <Wand2 size={20} />
          </div>
          <h1 className="text-xl font-bold text-slate-800 tracking-tight">Lumina <span className="text-brand-600">Design AI</span></h1>
        </div>
        <div className="flex items-center gap-4">
             {state.originalImage && (
              <button 
                onClick={() => {
                   setState(prev => ({...prev, originalImage: null, generatedImages: [], selectedImageId: null}))
                }}
                className="text-sm font-medium text-slate-500 hover:text-red-500 transition-colors"
              >
                Reset
              </button>
             )}
             <a href="https://github.com" target="_blank" rel="noreferrer" className="text-slate-400 hover:text-slate-800 transition-colors">
                <span className="text-xs font-semibold border border-slate-200 px-2 py-1 rounded-md">V1.0</span>
             </a>
        </div>
      </header>

      {/* --- Main Content --- */}
      <main className="flex-1 flex flex-col md:flex-row overflow-hidden relative">

        {/* --- Left / Top: Visualizer --- */}
        <div className="flex-1 flex flex-col min-w-0 bg-slate-100 relative">

          {/* Style Carousel (Overlay or Top Bar) */}
          {state.originalImage && (
            <div className="flex-none h-24 bg-white/80 backdrop-blur-md border-b border-white/50 flex items-center px-4 gap-3 overflow-x-auto scrollbar-hide z-10 shadow-sm">
               {DESIGN_STYLES.map((style) => (
                 <button
                    key={style.id}
                    onClick={() => handleGenerate(`Apply ${style.name} interior design style`, style.id)}
                    disabled={state.isGenerating}
                    className={`flex-none group relative rounded-xl overflow-hidden w-40 h-16 transition-all transform hover:scale-105 ${state.activeStyle === style.id ? 'ring-2 ring-brand-500 scale-105' : 'opacity-80 hover:opacity-100'}`}
                 >
                    <img src={style.image} alt={style.name} className="w-full h-full object-cover" />
                    <div className="absolute inset-0 bg-black/40 group-hover:bg-black/70 transition-colors duration-300 flex flex-col items-center justify-center p-2">
                       <span className="text-white text-xs font-bold shadow-sm">{style.name}</span>
                       <span className="text-[10px] text-gray-100 mt-1 text-center leading-tight opacity-0 group-hover:opacity-100 transition-opacity duration-300 hidden group-hover:block line-clamp-2">
                           {style.description}
                       </span>
                    </div>
                    {state.isGenerating && state.activeStyle === style.id && (
                        <div className="absolute inset-0 bg-black/60 flex items-center justify-center">
                            <Loader size="small" />
                        </div>
                    )}
                 </button>
               ))}
            </div>
          )}

          {/* Visualizer Area */}
          <div className="flex-1 relative flex items-center justify-center p-4 md:p-8 overflow-hidden">

             {!state.originalImage ? (
                // Upload State
                <div className="w-full max-w-md bg-white rounded-3xl border-2 border-dashed border-slate-300 p-12 flex flex-col items-center justify-center text-center hover:border-brand-400 transition-colors group cursor-pointer relative">
