             )}

             {error && (
                 <div className="absolute bottom-4 left-1/2 -translate-x-1/2 bg-red-50 text-red-600 px-4 py-2 rounded-lg shadow-lg border border-red-100 flex items-center gap-2 text-sm z-50">
                    <AlertCircle size={16} /> {error}
