        </div>

        {/* --- Right / Bottom: Chat --- */}
        <div className="w-full md:w-[400px] flex-none border-l border-slate-200 h-[40vh] md:h-auto z-20">
            <ChatInterface 
              messages={chatHistory} 
              onSendMessage={handleSendMessage}
              isTyping={isChatTyping}
            />
        </div>
      </main>
    </div>
  );
};

