          {/* Visualizer Area */}
          <div className="flex-1 relative flex items-center justify-center p-4 md:p-8 overflow-hidden">

             {!state.originalImage ? (
                // Upload State
                <div className="w-full max-w-md bg-white rounded-3xl border-2 border-dashed border-slate-300 p-12 flex flex-col items-center justify-center text-center hover:border-brand-400 transition-colors group cursor-pointer relative">
                    <input 
                      type="file" 
                      accept="image/*" 
                      onChange={handleFileUpload} 
                      className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                    />
                    <div className="w-20 h-20 bg-brand-50 rounded-full flex items-center justify-center mb-6 group-hover:bg-brand-100 transition-colors">
                      <ImageIcon className="text-brand-500" size={32} />
                    </div>
                    <h3 className="text-xl font-bold text-slate-800 mb-2">Upload your room</h3>
                    <p className="text-slate-500 text-sm mb-6">Drag & drop or click to upload a photo of your space to start the transformation.</p>
                    <button className="bg-brand-600 text-white px-6 py-2 rounded-full font-medium shadow-lg shadow-brand-200 group-hover:shadow-brand-300 transition-all flex items-center gap-2">
                        <Upload size={16} /> Upload Photo
                    </button>
                </div>
             ) : (
                // Comparison State
                <div className="relative w-full h-full max-w-5xl bg-white rounded-2xl shadow-2xl overflow-hidden border border-slate-200">
                   {state.isGenerating && (
                     <div className="absolute inset-0 z-30 bg-black/30 backdrop-blur-sm flex flex-col items-center justify-center text-white">
                        <Loader />
                        <p className="mt-4 font-medium animate-pulse">Designing your space...</p>
                     </div>
                   )}

                   {activeImage ? (
                     <ComparisonSlider 
                       beforeImage={state.originalImage} 
                       afterImage={activeImage} 
                     />
                   ) : (
                     <img src={state.originalImage} alt="Original" className="w-full h-full object-contain bg-slate-100" />
                   )}

                   {/* Download Action */}
                   {activeImage && (
                     <a 
                       href={activeImage} 
                       download="lumina-design.jpg"
