                 </div>

                 {/* Aspect Ratio Selector */}
                 <div className="relative group">
                    <div className="flex items-center gap-2 bg-slate-100 px-3 py-1.5 rounded-md text-sm font-medium text-slate-600 hover:bg-slate-200 cursor-pointer transition-colors border border-slate-200">
                        <Layout size={16} />
                        <span>{state.aspectRatio ? ASPECT_RATIOS.find(r => r.id === state.aspectRatio)?.label : '1:1 (Default)'}</span>
                        <ChevronDown size={14} className="opacity-50" />
                    </div>
                    {/* Dropdown Menu */}
                    <div className="absolute right-0 top-full mt-2 w-48 bg-white rounded-xl shadow-xl border border-slate-100 overflow-hidden hidden group-hover:block z-50">
                         <button
                           onClick={() => setState(prev => ({...prev, aspectRatio: null}))}
                           className={`w-full text-left px-4 py-2 text-sm hover:bg-brand-50 hover:text-brand-600 transition-colors ${!state.aspectRatio ? 'bg-brand-50 text-brand-600 font-medium' : 'text-slate-600'}`}
                        >
                            Default (1:1)
                        </button>
                        {ASPECT_RATIOS.map(ratio => (
                            <button
                                key={ratio.id}
                                onClick={() => setState(prev => ({...prev, aspectRatio: ratio.id}))}
                                className={`w-full text-left px-4 py-2 text-sm hover:bg-brand-50 hover:text-brand-600 transition-colors ${state.aspectRatio === ratio.id ? 'bg-brand-50 text-brand-600 font-medium' : 'text-slate-600'}`}
                            >
                                {ratio.label}
                            </button>
                        ))}
                    </div>
                 </div>

                 <div className="h-6 w-px bg-slate-200 mx-2"></div>

                 <button 
                   onClick={() => {
                      setState(prev => ({...prev, originalImage: null, generatedImages: [], selectedImageId: null, cameraAngle: null, aspectRatio: null}))
                   }}
                   className="text-sm font-medium text-slate-500 hover:text-red-500 transition-colors"
                 >
                   Reset
                 </button>
              </div>
             )}
             <a href="https://github.com" target="_blank" rel="noreferrer" className="text-slate-400 hover:text-slate-800 transition-colors">
                <span className="text-xs font-semibold border border-slate-200 px-2 py-1 rounded-md">V1.0</span>
             </a>
        </div>
      </header>

      {/* --- Main Content --- */}
      <main className="flex-1 flex flex-col md:flex-row overflow-hidden relative">

        {/* --- Left / Top: Visualizer --- */}
        <div className="flex-1 flex flex-col min-w-0 bg-slate-100 relative">

          {/* Style Carousel (Overlay or Top Bar) */}
          {state.originalImage && (
            <div className="flex-none h-24 bg-white/80 backdrop-blur-md border-b border-white/50 flex items-center px-4 gap-3 overflow-x-auto scrollbar-hide z-10 shadow-sm">
