import { GoogleGenAI, Type, FunctionDeclaration, Tool } from "@google/genai";
import { ChatMessage, MessageRole, GroundingLink } from '../types';

// Initialize Gemini Client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// --- Image Generation Service ---

interface DesignOptions {
  aspectRatio?: string; // "1:1", "3:4", "4:3", "9:16", "16:9"
  cameraAngle?: string; // e.g. "eye-level shot", "low-angle shot"
}

/**
 * Generates or edits a room design using Gemini 3 Pro Image.
 * It takes the original image and a prompt describing the desired outcome.
 */
export const generateRoomDesign = async (
  imageBase64: string,
  prompt: string,
  options: DesignOptions = {}
): Promise<string> => {
  try {
    // Strip header if present (e.g., "data:image/jpeg;base64,")
    const cleanBase64 = imageBase64.split(',')[1] || imageBase64;
    const { aspectRatio, cameraAngle } = options;

    let finalPrompt = `High-fidelity interior design makeover. ${prompt}.`;

    if (cameraAngle) {
      finalPrompt += ` Camera view: ${cameraAngle}.`;
    }

    finalPrompt += ` Maintain the exact architectural structure, perspective, and lighting direction of the original room. Render in 4k resolution with photorealistic textures, soft natural lighting, and realistic shadows. Style: Professional architectural photography, highly detailed.`;

    const config: any = {
      imageConfig: {
        imageSize: '2K',
      }
    };

    if (aspectRatio) {
      config.imageConfig.aspectRatio = aspectRatio;
    }

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview',
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: 'image/jpeg', // Assuming JPEG for simplicity, can detect from input
              data: cleanBase64
            }
          },
          {
            text: finalPrompt
          }
        ]
      },
      config: config
    });

    // Extract image from response
    // The response might contain text and/or images. We look for inlineData.
    if (response.candidates && response.candidates[0]?.content?.parts) {
        for (const part of response.candidates[0].content.parts) {
            if (part.inlineData && part.inlineData.data) {
                return `data:image/jpeg;base64,${part.inlineData.data}`;
            }
        }
    }

    throw new Error("No image generated.");
  } catch (error) {
    console.error("Image generation failed:", error);
    throw error;
  }
};


// --- Chat Service ---

// Function Declaration for the Chat Model to trigger design updates
const updateDesignFunction: FunctionDeclaration = {
  name: 'update_room_design',
  description: 'Updates the visual design of the room based on the user\'s description. Use this when the user asks to change colors, furniture, style, or specific visual elements.',
  parameters: {
    type: Type.OBJECT,
    properties: {
      visual_description: {
        type: Type.STRING,
        description: 'A detailed visual description of how the room should look. E.g., "A modern living room with a blue rug and white sofa". This description will be used as the prompt for the image generator.',
      },
    },
    required: ['visual_description'],
  },
};

const searchTool: Tool = {
  googleSearch: {}
};

const functionTool: Tool = {
  functionDeclarations: [updateDesignFunction]
};

/**
 * Sends a message to the design consultant (Gemini 3 Pro).
 * Supports search grounding and function calling for design updates.
 */
export const sendChatMessage = async (
  history: ChatMessage[],
  newMessage: string,
  onDesignUpdate: (description: string) => Promise<void>
): Promise<ChatMessage> => {

  // Format history for the API
  const contents = history.map(msg => ({
    role: msg.role === MessageRole.USER ? 'user' : 'model',
    parts: [{ text: msg.text }]
  }));

  // Add the new message
  contents.push({
    role: 'user',
    parts: [{ text: newMessage }]
  });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: contents,
      config: {
        systemInstruction: "You are an expert Interior Design Consultant. Help users redesign their rooms. If they ask for specific products or shopping advice, use Google Search. If they ask to change the look of the room (e.g., 'make the walls blue', 'switch to industrial style', 'change the angle'), use the update_room_design function. When calling update_room_design, provide a descriptive and complete visual prompt for the image generator that captures the user's intent.",
        tools: [searchTool, functionTool],
      }
    });

    const candidate = response.candidates?.[0];

    // Check for Function Calls
    const functionCalls = candidate?.content?.parts?.filter(p => p.functionCall).map(p => p.functionCall);

    let botText = "";

    if (functionCalls && functionCalls.length > 0) {
      for (const call of functionCalls) {
        if (call && call.name === 'update_room_design') {
          // Trigger the callback provided by the UI
          const args = call.args as any;
          botText += `(Updating design: "${args.visual_description}")... `;
          await onDesignUpdate(args.visual_description);
        }
      }
      // If the model only called a function, it might not have much text. 
      // We can append a confirmation if needed, or rely on the text part if present.
    }

    // Extract text response
    const textPart = candidate?.content?.parts?.find(p => p.text);
    if (textPart?.text) {
      botText += textPart.text;
    } else if (!botText) {
      botText = "I've updated the design for you!";
    }

    // Extract Grounding Metadata (Search results)
    const groundingLinks: GroundingLink[] = [];
    const chunks = candidate?.groundingMetadata?.groundingChunks;
    if (chunks) {
      chunks.forEach((chunk: any) => {
        if (chunk.web?.uri && chunk.web?.title) {
          groundingLinks.push({
            title: chunk.web.title,
            url: chunk.web.uri
          });
        }
      });
    }

    return {
      id: Date.now().toString(),
      role: MessageRole.MODEL,
      text: botText,
      timestamp: Date.now(),
      groundingLinks: groundingLinks.length > 0 ? groundingLinks : undefined
    };

  } catch (error) {
    console.error("Chat error:", error);
    return {
      id: Date.now().toString(),
      role: MessageRole.MODEL,
      text: "Sorry, I'm having trouble connecting to my design brain right now. Please try again.",
      timestamp: Date.now(),
      isError: true
    };
  }
};

export interface DesignStyle {
  id: string;
  name: string;
  description: string;
  image: string; // Placeholder or thumbnail
}

export enum MessageRole {
  USER = 'user',
  MODEL = 'model',
  SYSTEM = 'system'
}

export interface ChatMessage {
  id: string;
  role: MessageRole;
  text: string;
  timestamp: number;
  isError?: boolean;
  groundingLinks?: GroundingLink[];
}

export interface GroundingLink {
  title: string;
  url: string;
}

export interface GeneratedImage {
  id: string;
  url: string; // Base64 data URI
  prompt: string;
  styleName: string;
}

export interface SavedDesign {
  id: string;
  name: string;
  timestamp: number;
  originalImage: string;
  generatedImage: string;
  prompt: string;
  styleName: string;
}

export interface AppState {
  originalImage: string | null;
  generatedImages: GeneratedImage[];
  selectedImageId: string | null;
  isGenerating: boolean;
  activeStyle: string | null;
  cameraAngle: string | null;
  aspectRatio: string | null;
}

