        setSavedDesigns(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse saved designs", e);
      }
    }
  }, []);

  // --- Handlers ---

  // Handle Image Upload
  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      if (file.size > 10 * 1024 * 1024) { // 10MB limit
          setError("File too large. Please upload an image under 10MB.");
          return;
      }

      const reader = new FileReader();
      reader.onloadend = () => {
        setState((prev) => ({
          ...prev,
          originalImage: reader.result as string,
          generatedImages: [], // Clear previous results
          selectedImageId: null,
          activeStyle: null,
          cameraAngle: null,
          aspectRatio: null
        }));
        setError(null);

        // Add a system message to chat
        const newMsg: ChatMessage = {
            id: Date.now().toString(),
            role: MessageRole.MODEL,
            text: "Great photo! Choose a style from the carousel above, or describe how you want to change it.",
            timestamp: Date.now()
        };
        setChatHistory(prev => [...prev, newMsg]);
      };
      reader.readAsDataURL(file);
    }
  };

  // Generate Image from Style or Chat
  const handleGenerate = useCallback(async (prompt: string, styleId?: string, sourceImage?: string) => {
    // Determine which image to use as the base.
    // Use the explicitly passed sourceImage if available (for iterative updates),
    // otherwise fall back to the original uploaded image.
    const imageToProcess = sourceImage || state.originalImage;

    if (!imageToProcess) return;

    setState((prev) => ({ ...prev, isGenerating: true, activeStyle: styleId || null }));
    setError(null);

    try {
      const generatedImageBase64 = await generateRoomDesign(
        imageToProcess, 
        prompt, 
        { 
          cameraAngle: state.cameraAngle || undefined,
          aspectRatio: state.aspectRatio || undefined
        }
      );

      const newImage: GeneratedImage = {
        id: Date.now().toString(),
        url: generatedImageBase64,
        prompt: prompt,
        styleName: styleId ? DESIGN_STYLES.find(s => s.id === styleId)?.name || 'Custom' : 'Custom'
      };

      setState((prev) => ({
        ...prev,
        generatedImages: [...prev.generatedImages, newImage],
        selectedImageId: newImage.id,
        isGenerating: false,
      }));
    } catch (err) {
      console.error(err);
      setError("Failed to generate design. Please try again.");
      setState((prev) => ({ ...prev, isGenerating: false, activeStyle: null }));
    }
  }, [state.originalImage, state.cameraAngle, state.aspectRatio]);

  // Handle Chat Message
  const handleSendMessage = async (text: string) => {
    // Add User Message
    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: MessageRole.USER,
      text: text,
      timestamp: Date.now(),
    };
    setChatHistory((prev) => [...prev, userMsg]);
    setIsChatTyping(true);

    // Call Gemini Chat
    // Note: We pass a callback for "Design Updates" that the model can trigger
    const onDesignUpdate = async (description: string) => {
        if (!state.originalImage) {
            setError("Please upload an image first.");
            return;
        }

        // Logic for iterative refinement:
        // Check if there is a currently selected (generated) image (the 'after' image).
        // If so, use it as the source for the new generation to apply changes incrementally.
        const currentActiveImage = state.selectedImageId 
            ? state.generatedImages.find(img => img.id === state.selectedImageId)?.url 
            : null;

        // Use the active generated image if available, otherwise start from original
        const baseImage = currentActiveImage || state.originalImage;

        await handleGenerate(description, undefined, baseImage);
    };

    const responseMsg = await sendChatMessage([...chatHistory, userMsg], text, onDesignUpdate);

    setChatHistory((prev) => [...prev, responseMsg]);
    setIsChatTyping(false);
  };

  // --- Saved Design Handlers ---

  const handleOpenSaveModal = () => {
    setDesignName(`My Design ${savedDesigns.length + 1}`);
    setShowSaveModal(true);
  };

  const confirmSaveDesign = () => {
    if (!state.originalImage || !activeImage || !state.selectedImageId) return;

    const currentGeneratedImage = state.generatedImages.find(img => img.id === state.selectedImageId);
    if (!currentGeneratedImage) return;

    const newDesign: SavedDesign = {
      id: Date.now().toString(),
      name: designName,
      timestamp: Date.now(),
      originalImage: state.originalImage,
      generatedImage: activeImage,
      prompt: currentGeneratedImage.prompt,
      styleName: currentGeneratedImage.styleName
    };

    const updatedDesigns = [newDesign, ...savedDesigns];

    try {
      localStorage.setItem('lumina_saved_designs', JSON.stringify(updatedDesigns));
      setSavedDesigns(updatedDesigns);
      setShowSaveModal(false);
    } catch (e) {
      alert("Storage limit reached. Please delete some old designs to save new ones.");
    }
  };

  const deleteDesign = (id: string) => {
    const updatedDesigns = savedDesigns.filter(d => d.id !== id);
    localStorage.setItem('lumina_saved_designs', JSON.stringify(updatedDesigns));
    setSavedDesigns(updatedDesigns);
  };

  const loadDesign = (design: SavedDesign) => {
    // Restore state from saved design
    const restoredGeneratedImage: GeneratedImage = {
      id: Date.now().toString(), // New ID to avoid conflicts
      url: design.generatedImage,
      prompt: design.prompt,
      styleName: design.styleName
    };

    setState(prev => ({
      ...prev,
      originalImage: design.originalImage,
      generatedImages: [restoredGeneratedImage],
      selectedImageId: restoredGeneratedImage.id,
      activeStyle: null,
      isGenerating: false,
    }));

    setShowSavedList(false);

    // Add a chat message indicating context switch
    const newMsg: ChatMessage = {
        id: Date.now().toString(),
        role: MessageRole.SYSTEM,
        text: `Loaded design: "${design.name}"`,
        timestamp: Date.now()
    };
    setChatHistory(prev => [...prev, newMsg]);
  };

  // Derived State
  const activeImage = state.selectedImageId 
    ? state.generatedImages.find(img => img.id === state.selectedImageId)?.url 
    : null;

  return (
    <div className="flex flex-col h-screen overflow-hidden bg-slate-50">

      {/* --- Header --- */}
      <header className="flex-none h-16 bg-white border-b border-slate-200 flex items-center justify-between px-6 z-20 shadow-sm">
        <div className="flex items-center gap-2">
          <div className="bg-brand-600 p-2 rounded-lg text-white">
            <Wand2 size={20} />
          </div>
          <h1 className="text-xl font-bold text-slate-800 tracking-tight">Lumina <span className="text-brand-600">Design AI</span></h1>
        </div>
        <div className="flex items-center gap-4">
             {state.originalImage && (
              <div className="flex items-center gap-2">
                 {/* Camera Angle Selector */}
                 <div className="relative group">
                    <div className="flex items-center gap-2 bg-slate-100 px-3 py-1.5 rounded-md text-sm font-medium text-slate-600 hover:bg-slate-200 cursor-pointer transition-colors border border-slate-200">
                        <Camera size={16} />
                        <span>{state.cameraAngle ? CAMERA_ANGLES.find(a => a.id === state.cameraAngle)?.label : 'Default View'}</span>
                        <ChevronDown size={14} className="opacity-50" />
                    </div>
                    {/* Dropdown Menu */}
                    <div className="absolute right-0 top-full mt-2 w-40 bg-white rounded-xl shadow-xl border border-slate-100 overflow-hidden hidden group-hover:block z-50">
                        <button
                           onClick={() => setState(prev => ({...prev, cameraAngle: null}))}
                           className={`w-full text-left px-4 py-2 text-sm hover:bg-brand-50 hover:text-brand-600 transition-colors ${!state.cameraAngle ? 'bg-brand-50 text-brand-600 font-medium' : 'text-slate-600'}`}
                        >
                            Default View
                        </button>
                        {CAMERA_ANGLES.map(angle => (
                            <button
                                key={angle.id}
                                onClick={() => setState(prev => ({...prev, cameraAngle: angle.id}))}
                                className={`w-full text-left px-4 py-2 text-sm hover:bg-brand-50 hover:text-brand-600 transition-colors ${state.cameraAngle === angle.id ? 'bg-brand-50 text-brand-600 font-medium' : 'text-slate-600'}`}
                            >
                                {angle.label}
                            </button>
                        ))}
                    </div>
                 </div>

                 {/* Aspect Ratio Selector */}
                 <div className="relative group">
                    <div className="flex items-center gap-2 bg-slate-100 px-3 py-1.5 rounded-md text-sm font-medium text-slate-600 hover:bg-slate-200 cursor-pointer transition-colors border border-slate-200">
                        <Layout size={16} />
                        <span>{state.aspectRatio ? ASPECT_RATIOS.find(r => r.id === state.aspectRatio)?.label : '1:1 (Default)'}</span>
                        <ChevronDown size={14} className="opacity-50" />
                    </div>
                    {/* Dropdown Menu */}
                    <div className="absolute right-0 top-full mt-2 w-48 bg-white rounded-xl shadow-xl border border-slate-100 overflow-hidden hidden group-hover:block z-50">
                         <button
                           onClick={() => setState(prev => ({...prev, aspectRatio: null}))}
                           className={`w-full text-left px-4 py-2 text-sm hover:bg-brand-50 hover:text-brand-600 transition-colors ${!state.aspectRatio ? 'bg-brand-50 text-brand-600 font-medium' : 'text-slate-600'}`}
                        >
                            Default (1:1)
                        </button>
                        {ASPECT_RATIOS.map(ratio => (
