import React, { useState, useEffect, useCallback } from 'react';
import { Upload, Image as ImageIcon, Wand2, Download, AlertCircle, Camera, ChevronDown, Layout, Save, FolderHeart, X, Trash2, ExternalLink } from 'lucide-react';
import { generateRoomDesign, sendChatMessage } from './services/geminiService';
import { AppState, ChatMessage, GeneratedImage, MessageRole, SavedDesign } from './types';
import { DESIGN_STYLES, INITIAL_CHAT_MESSAGE } from './constants';
import ComparisonSlider from './components/ComparisonSlider';
import ChatInterface from './components/ChatInterface';

const CAMERA_ANGLES = [
  { id: 'eye-level shot', label: 'Eye-Level' },
  { id: 'low-angle shot', label: 'Low Angle' },
  { id: 'high-angle shot', label: 'High Angle' },
  { id: 'wide shot', label: 'Wide Shot' },
  { id: 'isometric view', label: 'Isometric' },
];

const ASPECT_RATIOS = [
  { id: '1:1', label: 'Square (1:1)' },
  { id: '16:9', label: 'Widescreen (16:9)' },
  { id: '9:16', label: 'Portrait (9:16)' },
  { id: '4:3', label: 'Standard (4:3)' },
  { id: '3:4', label: 'Vertical (3:4)' },
];

const App: React.FC = () => {
  // --- State ---
  const [state, setState] = useState<AppState>({
    originalImage: null,
    generatedImages: [],
    selectedImageId: null,
    isGenerating: false,
    activeStyle: null,
    cameraAngle: null,
    aspectRatio: null,
  });

  const [chatHistory, setChatHistory] = useState<ChatMessage[]>([
    {
      id: 'init',
      role: MessageRole.MODEL,
      text: INITIAL_CHAT_MESSAGE,
      timestamp: Date.now(),
    },
  ]);
  const [isChatTyping, setIsChatTyping] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // --- Saved Designs State ---
  const [savedDesigns, setSavedDesigns] = useState<SavedDesign[]>([]);
  const [showSaveModal, setShowSaveModal] = useState(false);
  const [showSavedList, setShowSavedList] = useState(false);
  const [designName, setDesignName] = useState('');

  // Load saved designs on mount
  useEffect(() => {
    const saved = localStorage.getItem('lumina_saved_designs');
    if (saved) {
      try {
        setSavedDesigns(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse saved designs", e);
      }
    }
  }, []);

  // --- Handlers ---

  // Handle Image Upload
  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      if (file.size > 10 * 1024 * 1024) { // 10MB limit
          setError("File too large. Please upload an image under 10MB.");
          return;
      }

      const reader = new FileReader();
      reader.onloadend = () => {
        setState((prev) => ({
          ...prev,
          originalImage: reader.result as string,
          generatedImages: [], // Clear previous results
          selectedImageId: null,
          activeStyle: null,
          cameraAngle: null,
          aspectRatio: null
        }));
        setError(null);

        // Add a system message to chat
        const newMsg: ChatMessage = {
            id: Date.now().toString(),
            role: MessageRole.MODEL,
            text: "Great photo! Choose a style from the carousel above, or describe how you want to change it.",
            timestamp: Date.now()
        };
        setChatHistory(prev => [...prev, newMsg]);
      };
      reader.readAsDataURL(file);
    }
  };

  // Generate Image from Style or Chat
  const handleGenerate = useCallback(async (prompt: string, styleId?: string, sourceImage?: string) => {
    // Determine which image to use as the base.
    // Use the explicitly passed sourceImage if available (for iterative updates),
    // otherwise fall back to the original uploaded image.
    const imageToProcess = sourceImage || state.originalImage;

    if (!imageToProcess) return;

    setState((prev) => ({ ...prev, isGenerating: true, activeStyle: styleId || null }));
    setError(null);

    try {
      const generatedImageBase64 = await generateRoomDesign(
        imageToProcess, 
        prompt, 
        { 
          cameraAngle: state.cameraAngle || undefined,
          aspectRatio: state.aspectRatio || undefined
        }
      );

      const newImage: GeneratedImage = {
        id: Date.now().toString(),
        url: generatedImageBase64,
        prompt: prompt,
        styleName: styleId ? DESIGN_STYLES.find(s => s.id === styleId)?.name || 'Custom' : 'Custom'
      };

      setState((prev) => ({
        ...prev,
        generatedImages: [...prev.generatedImages, newImage],
        selectedImageId: newImage.id,
        isGenerating: false,
      }));
    } catch (err) {
      console.error(err);
      setError("Failed to generate design. Please try again.");
      setState((prev) => ({ ...prev, isGenerating: false, activeStyle: null }));
    }
  }, [state.originalImage, state.cameraAngle, state.aspectRatio]);

  // Handle Chat Message
  const handleSendMessage = async (text: string) => {
    // Add User Message
    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: MessageRole.USER,
      text: text,
      timestamp: Date.now(),
    };
    setChatHistory((prev) => [...prev, userMsg]);
    setIsChatTyping(true);

    // Call Gemini Chat
    // Note: We pass a callback for "Design Updates" that the model can trigger
    const onDesignUpdate = async (prompt: string) => {
        if (!state.originalImage) {
            setError("Please upload an image first.");
            return;
        }

        // Logic for iterative refinement:
        // Check if there is a currently selected (generated) image (the 'after' image).
        // If so, use it as the source for the new generation to apply changes incrementally.
        // This effectively enables "Make the sofa red" to work on the current state.
        const currentActiveImage = state.selectedImageId 
            ? state.generatedImages.find(img => img.id === state.selectedImageId)?.url 
            : null;

        // Use the active generated image if available, otherwise start from original
        const baseImage = currentActiveImage || state.originalImage;

        await handleGenerate(prompt, undefined, baseImage);
    };

    const responseMsg = await sendChatMessage([...chatHistory, userMsg], text, onDesignUpdate);

    setChatHistory((prev) => [...prev, responseMsg]);
    setIsChatTyping(false);
  };

  // --- Saved Design Handlers ---

  const handleOpenSaveModal = () => {
    setDesignName(`My Design ${savedDesigns.length + 1}`);
    setShowSaveModal(true);
  };

  const confirmSaveDesign = () => {
    if (!state.originalImage || !activeImage || !state.selectedImageId) return;

