import { GoogleGenAI, Type, FunctionDeclaration, Tool } from "@google/genai";
import { ChatMessage, MessageRole, GroundingLink } from '../types';

// --- Image Generation Service ---

interface DesignOptions {
  aspectRatio?: string; // "1:1", "3:4", "4:3", "9:16", "16:9"
  cameraAngle?: string; // e.g. "eye-level shot", "low-angle shot"
}

/**
 * Generates or edits a room design using Gemini 3 Pro Image.
 * It takes the original image and a prompt describing the desired outcome.
 */
export const generateRoomDesign = async (
  imageBase64: string,
  prompt: string,
  options: DesignOptions = {}
): Promise<string> => {
  // Initialize client here to ensure we use the most recent API Key
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    // Strip header if present (e.g., "data:image/jpeg;base64,")
    const cleanBase64 = imageBase64.split(',')[1] || imageBase64;
    const { aspectRatio, cameraAngle } = options;

    let finalPrompt = `High-fidelity interior design makeover. ${prompt}.`;

    if (cameraAngle) {
      finalPrompt += ` Camera view: ${cameraAngle}.`;
    }

    finalPrompt += ` Maintain the exact architectural structure, perspective, and lighting direction of the original room. Render in 4k resolution with photorealistic textures. Apply high-quality material finishes such as velvet sofa fabrics, oak wood flooring, and matte finish cabinets. Soft natural lighting, and realistic shadows. Style: Professional architectural photography, highly detailed.`;

    const config: any = {
      imageConfig: {
        imageSize: '2K',
      }
    };

    if (aspectRatio) {
      config.imageConfig.aspectRatio = aspectRatio;
    }

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview',
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: 'image/jpeg', // Assuming JPEG for simplicity, can detect from input
              data: cleanBase64
            }
          },
          {
            text: finalPrompt
          }
        ]
      },
      config: config
    });

    // Extract image from response
    // The response might contain text and/or images. We look for inlineData.
    if (response.candidates && response.candidates[0]?.content?.parts) {
        for (const part of response.candidates[0].content.parts) {
            if (part.inlineData && part.inlineData.data) {
                return `data:image/jpeg;base64,${part.inlineData.data}`;
            }
        }
    }

    throw new Error("No image generated.");
  } catch (error) {
    console.error("Image generation failed:", error);
    throw error;
  }
};


// --- Chat Service ---

// Function Declaration for the Chat Model to trigger design updates
const updateDesignFunction: FunctionDeclaration = {
  name: 'update_room_design',
  description: 'Updates the visual design of the room based on the user\'s description. Use this when the user asks to change colors, furniture, style, or specific visual elements.',
  parameters: {
    type: Type.OBJECT,
    properties: {
      prompt: {
        type: Type.STRING,
        description: 'The instruction or description for the image generation model. If the user asks for a specific change (e.g., "make the sofa red"), pass that instruction. If they describe a new style, pass a visual description.',
      },
    },
    required: ['prompt'],
  },
};

const searchTool: Tool = {
  googleSearch: {}
};

const functionTool: Tool = {
  functionDeclarations: [updateDesignFunction]
};

/**
 * Sends a message to the design consultant (Gemini 3 Pro).
 * Supports search grounding and function calling for design updates.
 */
export const sendChatMessage = async (
  history: ChatMessage[],
  newMessage: string,
  onDesignUpdate: (prompt: string) => Promise<void>
): Promise<ChatMessage> => {
  // Initialize client here to ensure we use the most recent API Key
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Format history for the API
  const contents = history.map(msg => ({
    role: msg.role === MessageRole.USER ? 'user' : 'model',
    parts: [{ text: msg.text }]
  }));

  // Add the new message
  contents.push({
    role: 'user',
    parts: [{ text: newMessage }]
  });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: contents,
      config: {
        systemInstruction: "You are an expert Interior Design Consultant. Help users redesign their rooms. If they ask for specific products or shopping advice, use Google Search. If they ask to change the look of the room (e.g., 'make the walls blue', 'switch to industrial style', 'change the angle'), use the update_room_design function. When calling update_room_design, pass the user's specific instruction or a clear visual description as the 'prompt' argument to ensure the image generator understands the desired change.",
        tools: [searchTool, functionTool],
      }
    });

    const candidate = response.candidates?.[0];

    // Check for Function Calls
    const functionCalls = candidate?.content?.parts?.filter(p => p.functionCall).map(p => p.functionCall);

    let botText = "";

    if (functionCalls && functionCalls.length > 0) {
      for (const call of functionCalls) {
        if (call && call.name === 'update_room_design') {
          // Trigger the callback provided by the UI
          const args = call.args as any;
          botText += `(Updating design: "${args.prompt}")... `;
          await onDesignUpdate(args.prompt);
        }
      }
    }

    // Extract text response
    const textPart = candidate?.content?.parts?.find(p => p.text);
    if (textPart?.text) {
      botText += textPart.text;
    } else if (!botText) {
      botText = "I've started that design update for you!";
    }

    // Extract Grounding Metadata (Search results)
    const groundingLinks: GroundingLink[] = [];
    const chunks = candidate?.groundingMetadata?.groundingChunks;
    if (chunks) {
      chunks.forEach((chunk: any) => {
        if (chunk.web?.uri && chunk.web?.title) {
          groundingLinks.push({
            title: chunk.web.title,
            url: chunk.web.uri
          });
        }
      });
    }

    return {
      id: Date.now().toString(),
      role: MessageRole.MODEL,
      text: botText,
      timestamp: Date.now(),
      groundingLinks: groundingLinks.length > 0 ? groundingLinks : undefined
    };

  } catch (error) {
    console.error("Chat error:", error);
    return {
      id: Date.now().toString(),
      role: MessageRole.MODEL,
      text: "Sorry, I'm having trouble connecting to my design brain right now. Please try again.",
      timestamp: Date.now(),
      isError: true
    };
  }
};

import React, { useState, useEffect, useCallback } from 'react';
import { Upload, Image as ImageIcon, Wand2, Download, AlertCircle, Camera, ChevronDown, Layout, Save, FolderHeart, X, Trash2, ExternalLink, Key } from 'lucide-react';
import { generateRoomDesign, sendChatMessage } from './services/geminiService';
import { AppState, ChatMessage, GeneratedImage, MessageRole, SavedDesign } from './types';
import { DESIGN_STYLES, INITIAL_CHAT_MESSAGE } from './constants';
import ComparisonSlider from './components/ComparisonSlider';
import ChatInterface from './components/ChatInterface';

// Extend Window interface for AI Studio helpers
declare global {
  interface Window {
    aistudio: {
      hasSelectedApiKey: () => Promise<boolean>;
      openSelectKey: () => Promise<void>;
    };
  }
}

const CAMERA_ANGLES = [
  { id: 'eye-level shot', label: 'Eye-Level' },
  { id: 'low-angle shot', label: 'Low Angle' },
  { id: 'high-angle shot', label: 'High Angle' },
  { id: 'wide shot', label: 'Wide Shot' },
  { id: 'isometric view', label: 'Isometric' },
];

const ASPECT_RATIOS = [
  { id: '1:1', label: 'Square (1:1)' },
  { id: '16:9', label: 'Widescreen (16:9)' },
  { id: '9:16', label: 'Portrait (9:16)' },
  { id: '4:3', label: 'Standard (4:3)' },
  { id: '3:4', label: 'Vertical (3:4)' },
];

const App: React.FC = () => {
  // --- Access State ---
  const [hasAccess, setHasAccess] = useState(false);
  const [checkingAccess, setCheckingAccess] = useState(true);

  // --- App State ---
  const [state, setState] = useState<AppState>({
    originalImage: null,
    generatedImages: [],
    selectedImageId: null,
    isGenerating: false,
    activeStyle: null,
    cameraAngle: null,
    aspectRatio: null,
  });

  const [chatHistory, setChatHistory] = useState<ChatMessage[]>([
    {
      id: 'init',
      role: MessageRole.MODEL,
      text: INITIAL_CHAT_MESSAGE,
      timestamp: Date.now(),
    },
  ]);
  const [isChatTyping, setIsChatTyping] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // --- Saved Designs State ---
  const [savedDesigns, setSavedDesigns] = useState<SavedDesign[]>([]);
  const [showSaveModal, setShowSaveModal] = useState(false);
  const [showSavedList, setShowSavedList] = useState(false);
  const [designName, setDesignName] = useState('');

  // Check API Key on Mount
  useEffect(() => {
    const checkKey = async () => {
      try {
        if (window.aistudio && await window.aistudio.hasSelectedApiKey()) {
          setHasAccess(true);
        }
      } catch (e) {
        console.error("Error checking API key:", e);
      } finally {
        setCheckingAccess(false);
      }
    };
    checkKey();
  }, []);

  // Load saved designs on mount
  useEffect(() => {
    const saved = localStorage.getItem('lumina_saved_designs');
    if (saved) {
      try {
        setSavedDesigns(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse saved designs", e);
      }
    }
  }, []);

  // --- Handlers ---

  const handleAPIKeySelect = async () => {
    if (window.aistudio) {
      try {
        await window.aistudio.openSelectKey();
        // Assuming success to avoid race condition as per guidelines
        setHasAccess(true);
      } catch (e) {
        console.error("Error selecting key:", e);
        setError("Failed to select API key. Please try again.");
      }
    }
  };

  // Handle Image Upload
  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      if (file.size > 10 * 1024 * 1024) { // 10MB limit
          setError("File too large. Please upload an image under 10MB.");
          return;
      }

      const reader = new FileReader();
      reader.onloadend = () => {
        setState((prev) => ({
          ...prev,
          originalImage: reader.result as string,
          generatedImages: [], // Clear previous results
          selectedImageId: null,
          activeStyle: null,
          cameraAngle: null,
          aspectRatio: null
        }));
        setError(null);

        // Add a system message to chat
        const newMsg: ChatMessage = {
            id: Date.now().toString(),
            role: MessageRole.MODEL,
            text: "Great photo! Choose a style from the carousel above, or describe how you want to change it.",
            timestamp: Date.now()
        };
        setChatHistory(prev => [...prev, newMsg]);
      };
      reader.readAsDataURL(file);
    }
  };

  // Generate Image from Style or Chat
  const handleGenerate = useCallback(async (prompt: string, styleId?: string, sourceImage?: string) => {
    // Determine which image to use as the base.
    // Use the explicitly passed sourceImage if available (for iterative updates),
    // otherwise fall back to the original uploaded image.
    const imageToProcess = sourceImage || state.originalImage;

    if (!imageToProcess) return;

    setState((prev) => ({ ...prev, isGenerating: true, activeStyle: styleId || null }));
    setError(null);

    try {
      const generatedImageBase64 = await generateRoomDesign(
        imageToProcess, 
        prompt, 
        { 
          cameraAngle: state.cameraAngle || undefined,
          aspectRatio: state.aspectRatio || undefined
        }
      );

      const newImage: GeneratedImage = {
        id: Date.now().toString(),
        url: generatedImageBase64,
        prompt: prompt,
        styleName: styleId ? DESIGN_STYLES.find(s => s.id === styleId)?.name || 'Custom' : 'Custom'
      };

      setState((prev) => ({
        ...prev,
        generatedImages: [...prev.generatedImages, newImage],
        selectedImageId: newImage.id,
        isGenerating: false,
      }));
    } catch (err: any) {
      console.error(err);
      if (err.message && err.message.includes("403")) {
          setError("Access Denied. Please ensure you have selected a valid paid API key.");
          setHasAccess(false); // Force re-selection
      } else {
          setError("Failed to generate design. Please try again.");
      }
      setState((prev) => ({ ...prev, isGenerating: false, activeStyle: null }));
    }
  }, [state.originalImage, state.cameraAngle, state.aspectRatio]);

  // Handle Chat Message
  const handleSendMessage = async (text: string) => {
    // Add User Message
    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: MessageRole.USER,
      text: text,
      timestamp: Date.now(),
    };
    setChatHistory((prev) => [...prev, userMsg]);
    setIsChatTyping(true);

    // Call Gemini Chat
    // Note: We pass a callback for "Design Updates" that the model can trigger
    const onDesignUpdate = async (prompt: string) => {
        if (!state.originalImage) {
            setError("Please upload an image first.");
            return;
        }

        // Logic for iterative refinement:
        // Check if there is a currently selected (generated) image (the 'after' image).
        // If so, use it as the source for the new generation to apply changes incrementally.
        // This effectively enables "Make the sofa red" to work on the current state.
        const currentActiveImage = state.selectedImageId 
            ? state.generatedImages.find(img => img.id === state.selectedImageId)?.url 
            : null;

        // Use the active generated image if available, otherwise start from original
        const baseImage = currentActiveImage || state.originalImage;

        await handleGenerate(prompt, undefined, baseImage);
    };

    const responseMsg = await sendChatMessage([...chatHistory, userMsg], text, onDesignUpdate);

    setChatHistory((prev) => [...prev, responseMsg]);
    setIsChatTyping(false);
  };

  // --- Saved Design Handlers ---

  const handleOpenSaveModal = () => {
    setDesignName(`My Design ${savedDesigns.length + 1}`);
    setShowSaveModal(true);
  };

  const confirmSaveDesign = () => {
    if (!state.originalImage || !activeImage || !state.selectedImageId) return;

    const currentGeneratedImage = state.generatedImages.find(img => img.id === state.selectedImageId);
    if (!currentGeneratedImage) return;

    const newDesign: SavedDesign = {
      id: Date.now().toString(),
      name: designName,
      timestamp: Date.now(),
      originalImage: state.originalImage,
      generatedImage: activeImage,
      prompt: currentGeneratedImage.prompt,
      styleName: currentGeneratedImage.styleName
    };

    const updatedDesigns = [newDesign, ...savedDesigns];

    try {
      localStorage.setItem('lumina_saved_designs', JSON.stringify(updatedDesigns));
      setSavedDesigns(updatedDesigns);
      setShowSaveModal(false);
    } catch (e) {
      alert("Storage limit reached. Please delete some old designs to save new ones.");
    }
  };

  const deleteDesign = (id: string) => {
    const updatedDesigns = savedDesigns.filter(d => d.id !== id);
    localStorage.setItem('lumina_saved_designs', JSON.stringify(updatedDesigns));
    setSavedDesigns(updatedDesigns);
  };

  const loadDesign = (design: SavedDesign) => {
    // Restore state from saved design
    const restoredGeneratedImage: GeneratedImage = {
      id: Date.now().toString(), // New ID to avoid conflicts
      url: design.generatedImage,
      prompt: design.prompt,
      styleName: design.styleName
    };

    setState(prev => ({
      ...prev,
      originalImage: design.originalImage,
      generatedImages: [restoredGeneratedImage],
      selectedImageId: restoredGeneratedImage.id,
      activeStyle: null,
      isGenerating: false,
    }));

    setShowSavedList(false);

    // Add a chat message indicating context switch
    const newMsg: ChatMessage = {
        id: Date.now().toString(),
        role: MessageRole.SYSTEM,
        text: `Loaded design: "${design.name}"`,
        timestamp: Date.now()
    };
    setChatHistory(prev => [...prev, newMsg]);
  };

  // Derived State
  const activeImage = state.selectedImageId 
    ? state.generatedImages.find(img => img.id === state.selectedImageId)?.url 
    : null;


  // --- Access Control / Landing Page ---
  if (checkingAccess) {
    return (
      <div className="flex items-center justify-center h-screen bg-slate-50">
        <Loader size="normal" />
      </div>
    );
  }

  if (!hasAccess) {
    return (
      <div className="flex flex-col items-center justify-center h-screen bg-slate-50 px-4 text-center">
        <div className="bg-brand-600 p-4 rounded-2xl text-white mb-6 shadow-xl">
          <Wand2 size={48} />
        </div>
        <h1 className="text-4xl font-bold text-slate-800 mb-2">Lumina <span className="text-brand-600">Design AI</span></h1>
        <p className="text-slate-600 max-w-md mb-8">
          Transform your living space with professional AI interior design. 
          To get started, please select a billing-enabled Google Cloud Project API Key.
        </p>

        <button 
          onClick={handleAPIKeySelect}
          className="flex items-center gap-2 bg-brand-600 hover:bg-brand-700 text-white px-8 py-3 rounded-full font-bold text-lg shadow-lg hover:shadow-brand-300/50 transition-all"
        >
          <Key size={20} />
          Select API Key & Start
        </button>

        <p className="mt-6 text-xs text-slate-400">
          This app uses high-resolution imaging models that require a paid project. <br/>
          <a href="https://ai.google.dev/gemini-api/docs/billing" target="_blank" rel="noopener noreferrer" className="underline hover:text-brand-600">
            Learn more about billing
          </a>
        </p>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-screen overflow-hidden bg-slate-50">

      {/* --- Header --- */}
      <header className="flex-none h-16 bg-white border-b border-slate-200 flex items-center justify-between px-6 z-20 shadow-sm">
        <div className="flex items-center gap-2">
          <div className="bg-brand-600 p-2 rounded-lg text-white">
            <Wand2 size={20} />
          </div>
          <h1 className="text-xl font-bold text-slate-800 tracking-tight">Lumina <span className="text-brand-600">Design AI</span></h1>
        </div>
        <div className="flex items-center gap-4">
             {state.originalImage && (
              <div className="flex items-center gap-2">
                 {/* Camera Angle Selector */}
                 <div className="relative group">
                    <div className="flex items-center gap-2 bg-slate-100 px-3 py-1.5 rounded-md text-sm font-medium text-slate-600 hover:bg-slate-200 cursor-pointer transition-colors border border-slate-200">
                        <Camera size={16} />
                        <span>{state.cameraAngle ? CAMERA_ANGLES.find(a => a.id === state.cameraAngle)?.label : 'Default View'}</span>
                        <ChevronDown size={14} className="opacity-50" />
                    </div>
                    {/* Dropdown Menu */}
                    <div className="absolute right-0 top-full mt-2 w-40 bg-white rounded-xl shadow-xl border border-slate-100 overflow-hidden hidden group-hover:block z-50">
                        <button
                           onClick={() => setState(prev => ({...prev, cameraAngle: null}))}
                           className={`w-full text-left px-4 py-2 text-sm hover:bg-brand-50 hover:text-brand-600 transition-colors ${!state.cameraAngle ? 'bg-brand-50 text-brand-600 font-medium' : 'text-slate-600'}`}
                        >
                            Default View
                        </button>
                        {CAMERA_ANGLES.map(angle => (
                            <button
                                key={angle.id}
                                onClick={() => setState(prev => ({...prev, cameraAngle: angle.id}))}
                                className={`w-full text-left px-4 py-2 text-sm hover:bg-brand-50 hover:text-brand-600 transition-colors ${state.cameraAngle === angle.id ? 'bg-brand-50 text-brand-600 font-medium' : 'text-slate-600'}`}
                            >
                                {angle.label}
                            </button>
                        ))}
                    </div>
                 </div>

                 {/* Aspect Ratio Selector */}
                 <div className="relative group">
                    <div className="flex items-center gap-2 bg-slate-100 px-3 py-1.5 rounded-md text-sm font-medium text-slate-600 hover:bg-slate-200 cursor-pointer transition-colors border border-slate-200">
                        <Layout size={16} />
                        <span>{state.aspectRatio ? ASPECT_RATIOS.find(r => r.id === state.aspectRatio)?.label : '1:1 (Default)'}</span>
                        <ChevronDown size={14} className="opacity-50" />
                    </div>
                    {/* Dropdown Menu */}
                    <div className="absolute right-0 top-full mt-2 w-48 bg-white rounded-xl shadow-xl border border-slate-100 overflow-hidden hidden group-hover:block z-50">
                         <button
                           onClick={() => setState(prev => ({...prev, aspectRatio: null}))}
                           className={`w-full text-left px-4 py-2 text-sm hover:bg-brand-50 hover:text-brand-600 transition-colors ${!state.aspectRatio ? 'bg-brand-50 text-brand-600 font-medium' : 'text-slate-600'}`}
                        >
                            Default (1:1)
                        </button>
                        {ASPECT_RATIOS.map(ratio => (
                            <button
                                key={ratio.id}
                                onClick={() => setState(prev => ({...prev, aspectRatio: ratio.id}))}
                                className={`w-full text-left px-4 py-2 text-sm hover:bg-brand-50 hover:text-brand-600 transition-colors ${state.aspectRatio === ratio.id ? 'bg-brand-50 text-brand-600 font-medium' : 'text-slate-600'}`}
                            >
                                {ratio.label}
                            </button>
                        ))}
                    </div>
                 </div>

                 <div className="h-6 w-px bg-slate-200 mx-2"></div>

                 <button 
                   onClick={() => {
                      setState(prev => ({...prev, originalImage: null, generatedImages: [], selectedImageId: null, cameraAngle: null, aspectRatio: null}))
                   }}
                   className="text-sm font-medium text-slate-500 hover:text-red-500 transition-colors"
                 >
                   Reset
                 </button>
              </div>
             )}

             <div className="h-6 w-px bg-slate-200 hidden md:block"></div>

             {/* My Designs Button */}
             <button
               onClick={() => setShowSavedList(true)}
               className="flex items-center gap-2 text-sm font-medium text-slate-600 hover:text-brand-600 transition-colors"
             >
               <FolderHeart size={18} />
               <span className="hidden sm:inline">My Designs</span>
             </button>

             <a href="https://github.com" target="_blank" rel="noreferrer" className="text-slate-400 hover:text-slate-800 transition-colors ml-2">
                <span className="text-xs font-semibold border border-slate-200 px-2 py-1 rounded-md">V1.0</span>
             </a>
        </div>
      </header>

      {/* --- Main Content --- */}
      <main className="flex-1 flex flex-col md:flex-row overflow-hidden relative">

        {/* --- Left / Top: Visualizer --- */}
        <div className="flex-1 flex flex-col min-w-0 bg-slate-100 relative">

          {/* Style Carousel (Overlay or Top Bar) */}
          {state.originalImage && (
            <div className="flex-none h-24 bg-white/80 backdrop-blur-md border-b border-white/50 flex items-center px-4 gap-3 overflow-x-auto scrollbar-hide z-10 shadow-sm">
               {DESIGN_STYLES.map((style) => (
                 <button
                    key={style.id}
                    onClick={() => handleGenerate(`Apply ${style.name} interior design style`, style.id)}
                    disabled={state.isGenerating}
                    className={`flex-none group relative rounded-xl overflow-hidden w-40 h-16 transition-all transform hover:scale-105 ${state.activeStyle === style.id ? 'ring-2 ring-brand-500 scale-105' : 'opacity-80 hover:opacity-100'}`}
                 >
                    <img src={style.image} alt={style.name} className="w-full h-full object-cover" />
                    <div className="absolute inset-0 bg-black/40 group-hover:bg-black/70 transition-colors duration-300 flex flex-col items-center justify-center p-2">
                       <span className="text-white text-xs font-bold shadow-sm">{style.name}</span>
                       <span className="text-[10px] text-gray-100 mt-1 text-center leading-tight opacity-0 group-hover:opacity-100 transition-opacity duration-300 hidden group-hover:block line-clamp-2">
                           {style.description}
                       </span>
                    </div>
                    {state.isGenerating && state.activeStyle === style.id && (
                        <div className="absolute inset-0 bg-black/60 flex items-center justify-center">
                            <Loader size="small" />
                        </div>
                    )}
                 </button>
               ))}
            </div>
          )}

          {/* Visualizer Area */}
          <div className="flex-1 relative flex items-center justify-center p-4 md:p-8 overflow-hidden">

             {!state.originalImage ? (
                // Upload State
                <div className="w-full max-w-md bg-white rounded-3xl border-2 border-dashed border-slate-300 p-12 flex flex-col items-center justify-center text-center hover:border-brand-400 transition-colors group cursor-pointer relative">
                    <input 
                      type="file" 
                      accept="image/*" 
                      onChange={handleFileUpload} 
                      className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                    />
                    <div className="w-20 h-20 bg-brand-50 rounded-full flex items-center justify-center mb-6 group-hover:bg-brand-100 transition-colors">
                      <ImageIcon className="text-brand-500" size={32} />
                    </div>
                    <h3 className="text-xl font-bold text-slate-800 mb-2">Upload your room</h3>
                    <p className="text-slate-500 text-sm mb-6">Drag & drop or click to upload a photo of your space to start the transformation.</p>
                    <button className="bg-brand-600 text-white px-6 py-2 rounded-full font-medium shadow-lg shadow-brand-200 group-hover:shadow-brand-300 transition-all flex items-center gap-2">
                        <Upload size={16} /> Upload Photo
                    </button>
                </div>
             ) : (
                // Comparison State
                <div className="relative w-full h-full max-w-5xl bg-white rounded-2xl shadow-2xl overflow-hidden border border-slate-200">
                   {state.isGenerating && (
                     <div className="absolute inset-0 z-30 bg-black/30 backdrop-blur-sm flex flex-col items-center justify-center text-white">
                        <Loader />
                        <p className="mt-4 font-medium animate-pulse">Designing your space...</p>
                     </div>
                   )}

                   {activeImage ? (
                     <ComparisonSlider 
                       beforeImage={state.originalImage} 
                       afterImage={activeImage} 
                     />
                   ) : (
                     <img src={state.originalImage} alt="Original" className="w-full h-full object-contain bg-slate-100" />
                   )}

                   {/* Action Buttons */}
                   {activeImage && (
                     <div className="absolute bottom-6 right-6 z-20 flex items-center gap-3">
                        {/* Save Button */}
                        <button 
                          onClick={handleOpenSaveModal}
                          className="bg-white/90 hover:bg-white text-slate-800 p-3 rounded-full shadow-lg backdrop-blur-sm transition-transform hover:scale-110"
                          title="Save Design"
                        >
                          <Save size={20} />
                        </button>
                        {/* Download Button */}
                        <a 
                          href={activeImage} 
                          download="lumina-design.jpg"
                          className="bg-white/90 hover:bg-white text-slate-800 p-3 rounded-full shadow-lg backdrop-blur-sm transition-transform hover:scale-110"
                          title="Download Design"
                        >
                          <Download size={20} />
                        </a>
                     </div>
                   )}
                </div>
             )}

             {error && (
                 <div className="absolute bottom-4 left-1/2 -translate-x-1/2 bg-red-50 text-red-600 px-4 py-2 rounded-lg shadow-lg border border-red-100 flex items-center gap-2 text-sm z-50">
                    <AlertCircle size={16} /> {error}
                 </div>
             )}

          </div>
        </div>

        {/* --- Right / Bottom: Chat --- */}
        <div className="w-full md:w-[400px] flex-none border-l border-slate-200 h-[40vh] md:h-auto z-20">
            <ChatInterface 
              messages={chatHistory} 
              onSendMessage={handleSendMessage}
              isTyping={isChatTyping}
            />
        </div>
      </main>

      {/* --- Modals --- */}

      {/* Save Design Modal */}
      {showSaveModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm">
          <div className="bg-white rounded-2xl shadow-xl w-full max-w-sm p-6 transform transition-all">
            <h3 className="text-lg font-bold text-slate-800 mb-4">Save Your Design</h3>
            <div className="mb-4">
              <label className="block text-sm font-medium text-slate-600 mb-1">Design Name</label>
              <input 
                type="text" 
                value={designName} 
                onChange={(e) => setDesignName(e.target.value)} 
                className="w-full border border-slate-200 rounded-lg px-3 py-2 focus:ring-2 focus:ring-brand-500 focus:outline-none"
                placeholder="e.g. Dream Living Room"
                autoFocus
              />
            </div>
            <div className="flex items-center justify-end gap-2">
              <button 
                onClick={() => setShowSaveModal(false)}
                className="px-4 py-2 text-slate-600 hover:bg-slate-100 rounded-lg font-medium"
              >
                Cancel
              </button>
              <button 
                onClick={confirmSaveDesign}
                disabled={!designName.trim()}
                className="px-4 py-2 bg-brand-600 hover:bg-brand-700 text-white rounded-lg font-medium disabled:opacity-50"
              >
                Save
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Saved Designs List Modal */}
      {showSavedList && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm">
          <div className="bg-white rounded-2xl shadow-xl w-full max-w-2xl h-[80vh] flex flex-col overflow-hidden">
            <div className="p-4 border-b border-slate-200 flex items-center justify-between">
              <h3 className="text-lg font-bold text-slate-800 flex items-center gap-2">
                <FolderHeart className="text-brand-600" /> My Saved Designs
              </h3>
              <button 
                onClick={() => setShowSavedList(false)}
                className="p-1 text-slate-400 hover:text-slate-600 rounded-full hover:bg-slate-100"
              >
                <X size={20} />
              </button>
            </div>

            <div className="flex-1 overflow-y-auto p-4 bg-slate-50">
              {savedDesigns.length === 0 ? (
                <div className="flex flex-col items-center justify-center h-full text-slate-400">
                  <FolderHeart size={48} className="mb-2 opacity-50" />
                  <p>No saved designs yet.</p>
                </div>
              ) : (
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                  {savedDesigns.map(design => (
                    <div key={design.id} className="bg-white rounded-xl border border-slate-200 shadow-sm hover:shadow-md transition-shadow overflow-hidden flex flex-col">
                      <div className="aspect-[4/3] relative bg-slate-100">
                        <img src={design.generatedImage} alt={design.name} className="w-full h-full object-cover" />
                        <div className="absolute inset-0 bg-gradient-to-t from-black/50 to-transparent opacity-0 hover:opacity-100 transition-opacity flex items-end justify-between p-3">
                           <span className="text-white text-xs font-medium">{design.styleName}</span>
                        </div>
                      </div>
                      <div className="p-3 flex-1 flex flex-col">
                        <div className="flex items-start justify-between mb-2">
                          <div>
                            <h4 className="font-semibold text-slate-800 text-sm">{design.name}</h4>
                            <p className="text-xs text-slate-500">{new Date(design.timestamp).toLocaleDateString()}</p>
                          </div>
                          <button 
                            onClick={() => deleteDesign(design.id)}
                            className="text-slate-400 hover:text-red-500 p-1"
                            title="Delete"
                          >
                            <Trash2 size={14} />
                          </button>
                        </div>
                        <p className="text-xs text-slate-500 line-clamp-2 mb-3 flex-1">{design.prompt}</p>
                        <button 
                           onClick={() => loadDesign(design)}
                           className="w-full py-1.5 bg-brand-50 hover:bg-brand-100 text-brand-700 text-xs font-semibold rounded-lg flex items-center justify-center gap-1 transition-colors"
                        >
                           <ExternalLink size={12} /> Open Design
                        </button>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>
        </div>
      )}

    </div>
  );
};

// Simple Loading Spinner Component
const Loader: React.FC<{ size?: 'small' | 'normal' }> = ({ size = 'normal' }) => (
    <div className={`rounded-full border-2 border-current border-t-transparent animate-spin ${size === 'small' ? 'w-4 h-4' : 'w-10 h-10'}`}></div>
);

export default App;

import React, { useState, useEffect, useCallback } from 'react';
import { Upload, Image as ImageIcon, Wand2, Download, AlertCircle, Camera, ChevronDown, Layout, Save, FolderHeart, X, Trash2, ExternalLink, Key } from 'lucide-react';
import { generateRoomDesign, sendChatMessage } from './services/geminiService';
import { AppState, ChatMessage, GeneratedImage, MessageRole, SavedDesign } from './types';
import { DESIGN_STYLES, INITIAL_CHAT_MESSAGE } from './constants';
import ComparisonSlider from './components/ComparisonSlider';
import ChatInterface from './components/ChatInterface';

// Extend Window interface for AI Studio helpers
declare global {
  interface AIStudio {
    hasSelectedApiKey(): Promise<boolean>;
    openSelectKey(): Promise<void>;
  }
}

const CAMERA_ANGLES = [
  { id: 'eye-level shot', label: 'Eye-Level' },
  { id: 'low-angle shot', label: 'Low Angle' },
  { id: 'high-angle shot', label: 'High Angle' },
  { id: 'wide shot', label: 'Wide Shot' },
  { id: 'isometric view', label: 'Isometric' },
];

const ASPECT_RATIOS = [
  { id: '1:1', label: 'Square (1:1)' },
  { id: '16:9', label: 'Widescreen (16:9)' },
  { id: '9:16', label: 'Portrait (9:16)' },
  { id: '4:3', label: 'Standard (4:3)' },
  { id: '3:4', label: 'Vertical (3:4)' },
];

const App: React.FC = () => {
  // --- Access State ---
  const [hasAccess, setHasAccess] = useState(false);
  const [checkingAccess, setCheckingAccess] = useState(true);

  // --- App State ---
  const [state, setState] = useState<AppState>({
    originalImage: null,
    generatedImages: [],
    selectedImageId: null,
    isGenerating: false,
    activeStyle: null,
    cameraAngle: null,
    aspectRatio: null,
  });

  const [chatHistory, setChatHistory] = useState<ChatMessage[]>([
    {
      id: 'init',
      role: MessageRole.MODEL,
      text: INITIAL_CHAT_MESSAGE,
      timestamp: Date.now(),
    },
  ]);
  const [isChatTyping, setIsChatTyping] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // --- Saved Designs State ---
  const [savedDesigns, setSavedDesigns] = useState<SavedDesign[]>([]);
  const [showSaveModal, setShowSaveModal] = useState(false);
  const [showSavedList, setShowSavedList] = useState(false);
  const [designName, setDesignName] = useState('');

  // Check API Key on Mount
  useEffect(() => {
    const checkKey = async () => {
      try {
        if (window.aistudio && await window.aistudio.hasSelectedApiKey()) {
          setHasAccess(true);
        }
      } catch (e) {
        console.error("Error checking API key:", e);
      } finally {
        setCheckingAccess(false);
      }
    };
    checkKey();
  }, []);

  // Load saved designs on mount
  useEffect(() => {
    const saved = localStorage.getItem('lumina_saved_designs');
    if (saved) {
      try {
        setSavedDesigns(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse saved designs", e);
      }
    }
  }, []);

  // --- Handlers ---

  const handleAPIKeySelect = async () => {
    if (window.aistudio) {
      try {
        await window.aistudio.openSelectKey();
        // Assuming success to avoid race condition as per guidelines
        setHasAccess(true);
      } catch (e) {
        console.error("Error selecting key:", e);
        setError("Failed to select API key. Please try again.");
      }
    }
  };

  // Handle Image Upload
  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      if (file.size > 10 * 1024 * 1024) { // 10MB limit
          setError("File too large. Please upload an image under 10MB.");
          return;
      }

      const reader = new FileReader();
      reader.onloadend = () => {
        setState((prev) => ({
          ...prev,
          originalImage: reader.result as string,
          generatedImages: [], // Clear previous results
          selectedImageId: null,
          activeStyle: null,
          cameraAngle: null,
          aspectRatio: null
        }));
        setError(null);

        // Add a system message to chat
        const newMsg: ChatMessage = {
            id: Date.now().toString(),
            role: MessageRole.MODEL,
            text: "Great photo! Choose a style from the carousel above, or describe how you want to change it.",
            timestamp: Date.now()
        };
        setChatHistory(prev => [...prev, newMsg]);
      };
      reader.readAsDataURL(file);
    }
  };

  // Generate Image from Style or Chat
  const handleGenerate = useCallback(async (prompt: string, styleId?: string, sourceImage?: string) => {
    // Determine which image to use as the base.
    // Use the explicitly passed sourceImage if available (for iterative updates),
    // otherwise fall back to the original uploaded image.
    const imageToProcess = sourceImage || state.originalImage;

    if (!imageToProcess) return;

    setState((prev) => ({ ...prev, isGenerating: true, activeStyle: styleId || null }));
    setError(null);

    try {
      const generatedImageBase64 = await generateRoomDesign(
        imageToProcess, 
        prompt, 
        { 
          cameraAngle: state.cameraAngle || undefined,
          aspectRatio: state.aspectRatio || undefined
        }
      );

      const newImage: GeneratedImage = {
        id: Date.now().toString(),
        url: generatedImageBase64,
        prompt: prompt,
        styleName: styleId ? DESIGN_STYLES.find(s => s.id === styleId)?.name || 'Custom' : 'Custom'
      };

      setState((prev) => ({
        ...prev,
        generatedImages: [...prev.generatedImages, newImage],
        selectedImageId: newImage.id,
        isGenerating: false,
      }));
    } catch (err: any) {
      console.error(err);
      if (err.message && err.message.includes("403")) {
          setError("Access Denied. Please ensure you have selected a valid paid API key.");
          setHasAccess(false); // Force re-selection
      } else {
          setError("Failed to generate design. Please try again.");
      }
      setState((prev) => ({ ...prev, isGenerating: false, activeStyle: null }));
    }
  }, [state.originalImage, state.cameraAngle, state.aspectRatio]);

  // Handle Chat Message
  const handleSendMessage = async (text: string) => {
    // Add User Message
    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: MessageRole.USER,
      text: text,
      timestamp: Date.now(),
    };
    setChatHistory((prev) => [...prev, userMsg]);
    setIsChatTyping(true);

    // Call Gemini Chat
    // Note: We pass a callback for "Design Updates" that the model can trigger
    const onDesignUpdate = async (prompt: string) => {
        if (!state.originalImage) {
            setError("Please upload an image first.");
            return;
        }

        // Logic for iterative refinement:
        // Check if there is a currently selected (generated) image (the 'after' image).
        // If so, use it as the source for the new generation to apply changes incrementally.
        // This effectively enables "Make the sofa red" to work on the current state.
        const currentActiveImage = state.selectedImageId 
            ? state.generatedImages.find(img => img.id === state.selectedImageId)?.url 
            : null;

        // Use the active generated image if available, otherwise start from original
        const baseImage = currentActiveImage || state.originalImage;

        await handleGenerate(prompt, undefined, baseImage);
    };

    const responseMsg = await sendChatMessage([...chatHistory, userMsg], text, onDesignUpdate);

    setChatHistory((prev) => [...prev, responseMsg]);
    setIsChatTyping(false);
  };

  // --- Saved Design Handlers ---

  const handleOpenSaveModal = () => {
    setDesignName(`My Design ${savedDesigns.length + 1}`);
    setShowSaveModal(true);
  };

  const confirmSaveDesign = () => {
    if (!state.originalImage || !activeImage || !state.selectedImageId) return;

    const currentGeneratedImage = state.generatedImages.find(img => img.id === state.selectedImageId);
    if (!currentGeneratedImage) return;

    const newDesign: SavedDesign = {
      id: Date.now().toString(),
      name: designName,
      timestamp: Date.now(),
      originalImage: state.originalImage,
      generatedImage: activeImage,
      prompt: currentGeneratedImage.prompt,
      styleName: currentGeneratedImage.styleName
    };

    const updatedDesigns = [newDesign, ...savedDesigns];

    try {
      localStorage.setItem('lumina_saved_designs', JSON.stringify(updatedDesigns));
      setSavedDesigns(updatedDesigns);
      setShowSaveModal(false);
    } catch (e) {
      alert("Storage limit reached. Please delete some old designs to save new ones.");
    }
  };

  const deleteDesign = (id: string) => {
    const updatedDesigns = savedDesigns.filter(d => d.id !== id);
    localStorage.setItem('lumina_saved_designs', JSON.stringify(updatedDesigns));
    setSavedDesigns(updatedDesigns);
  };

  const loadDesign = (design: SavedDesign) => {
    // Restore state from saved design
    const restoredGeneratedImage: GeneratedImage = {
      id: Date.now().toString(), // New ID to avoid conflicts
      url: design.generatedImage,
      prompt: design.prompt,
      styleName: design.styleName
    };

    setState(prev => ({
      ...prev,
      originalImage: design.originalImage,
      generatedImages: [restoredGeneratedImage],
      selectedImageId: restoredGeneratedImage.id,
      activeStyle: null,
      isGenerating: false,
    }));

    setShowSavedList(false);

    // Add a chat message indicating context switch
    const newMsg: ChatMessage = {
        id: Date.now().toString(),
        role: MessageRole.SYSTEM,
        text: `Loaded design: "${design.name}"`,
        timestamp: Date.now()
    };
    setChatHistory(prev => [...prev, newMsg]);
  };

  // Derived State
  const activeImage = state.selectedImageId 
    ? state.generatedImages.find(img => img.id === state.selectedImageId)?.url 
    : null;


  // --- Access Control / Landing Page ---
  if (checkingAccess) {
    return (
      <div className="flex items-center justify-center h-screen bg-slate-50">
        <Loader size="normal" />
      </div>
    );
  }

  if (!hasAccess) {
    return (
      <div className="flex flex-col items-center justify-center h-screen bg-slate-50 px-4 text-center">
        <div className="bg-brand-600 p-4 rounded-2xl text-white mb-6 shadow-xl">
          <Wand2 size={48} />
        </div>
        <h1 className="text-4xl font-bold text-slate-800 mb-2">Lumina <span className="text-brand-600">Design AI</span></h1>
        <p className="text-slate-600 max-w-md mb-8">
          Transform your living space with professional AI interior design. 
          To get started, please select a billing-enabled Google Cloud Project API Key.
        </p>

        <button 
          onClick={handleAPIKeySelect}
          className="flex items-center gap-2 bg-brand-600 hover:bg-brand-700 text-white px-8 py-3 rounded-full font-bold text-lg shadow-lg hover:shadow-brand-300/50 transition-all"
        >
          <Key size={20} />
          Select API Key & Start
        </button>

        <p className="mt-6 text-xs text-slate-400">
          This app uses high-resolution imaging models that require a paid project. <br/>
          <a href="https://ai.google.dev/gemini-api/docs/billing" target="_blank" rel="noopener noreferrer" className="underline hover:text-brand-600">
            Learn more about billing
          </a>
        </p>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-screen overflow-hidden bg-slate-50">

      {/* --- Header --- */}
      <header className="flex-none h-16 bg-white border-b border-slate-200 flex items-center justify-between px-6 z-20 shadow-sm">
        <div className="flex items-center gap-2">
          <div className="bg-brand-600 p-2 rounded-lg text-white">
            <Wand2 size={20} />
          </div>
          <h1 className="text-xl font-bold text-slate-800 tracking-tight">Lumina <span className="text-brand-600">Design AI</span></h1>
        </div>
        <div className="flex items-center gap-4">
             {state.originalImage && (
              <div className="flex items-center gap-2">
                 {/* Camera Angle Selector */}
                 <div className="relative group">
                    <div className="flex items-center gap-2 bg-slate-100 px-3 py-1.5 rounded-md text-sm font-medium text-slate-600 hover:bg-slate-200 cursor-pointer transition-colors border border-slate-200">
                        <Camera size={16} />
                        <span>{state.cameraAngle ? CAMERA_ANGLES.find(a => a.id === state.cameraAngle)?.label : 'Default View'}</span>
                        <ChevronDown size={14} className="opacity-50" />
                    </div>
                    {/* Dropdown Menu */}
                    <div className="absolute right-0 top-full mt-2 w-40 bg-white rounded-xl shadow-xl border border-slate-100 overflow-hidden hidden group-hover:block z-50">
                        <button
                           onClick={() => setState(prev => ({...prev, cameraAngle: null}))}
                           className={`w-full text-left px-4 py-2 text-sm hover:bg-brand-50 hover:text-brand-600 transition-colors ${!state.cameraAngle ? 'bg-brand-50 text-brand-600 font-medium' : 'text-slate-600'}`}
                        >
                            Default View
                        </button>
                        {CAMERA_ANGLES.map(angle => (
                            <button
                                key={angle.id}
                                onClick={() => setState(prev => ({...prev, cameraAngle: angle.id}))}
                                className={`w-full text-left px-4 py-2 text-sm hover:bg-brand-50 hover:text-brand-600 transition-colors ${state.cameraAngle === angle.id ? 'bg-brand-50 text-brand-600 font-medium' : 'text-slate-600'}`}
                            >
                                {angle.label}
                            </button>
                        ))}
                    </div>
                 </div>

                 {/* Aspect Ratio Selector */}
                 <div className="relative group">
                    <div className="flex items-center gap-2 bg-slate-100 px-3 py-1.5 rounded-md text-sm font-medium text-slate-600 hover:bg-slate-200 cursor-pointer transition-colors border border-slate-200">
                        <Layout size={16} />
                        <span>{state.aspectRatio ? ASPECT_RATIOS.find(r => r.id === state.aspectRatio)?.label : '1:1 (Default)'}</span>
                        <ChevronDown size={14} className="opacity-50" />
                    </div>
                    {/* Dropdown Menu */}
                    <div className="absolute right-0 top-full mt-2 w-48 bg-white rounded-xl shadow-xl border border-slate-100 overflow-hidden hidden group-hover:block z-50">
                         <button
                           onClick={() => setState(prev => ({...prev, aspectRatio: null}))}
                           className={`w-full text-left px-4 py-2 text-sm hover:bg-brand-50 hover:text-brand-600 transition-colors ${!state.aspectRatio ? 'bg-brand-50 text-brand-600 font-medium' : 'text-slate-600'}`}
                        >
                            Default (1:1)
                        </button>
                        {ASPECT_RATIOS.map(ratio => (
                            <button
                                key={ratio.id}
                                onClick={() => setState(prev => ({...prev, aspectRatio: ratio.id}))}
                                className={`w-full text-left px-4 py-2 text-sm hover:bg-brand-50 hover:text-brand-600 transition-colors ${state.aspectRatio === ratio.id ? 'bg-brand-50 text-brand-600 font-medium' : 'text-slate-600'}`}
                            >
                                {ratio.label}
                            </button>
                        ))}
                    </div>
                 </div>

                 <div className="h-6 w-px bg-slate-200 mx-2"></div>

                 <button 
                   onClick={() => {
                      setState(prev => ({...prev, originalImage: null, generatedImages: [], selectedImageId: null, cameraAngle: null, aspectRatio: null}))
                   }}
                   className="text-sm font-medium text-slate-500 hover:text-red-500 transition-colors"
                 >
                   Reset
                 </button>
              </div>
             )}

             <div className="h-6 w-px bg-slate-200 hidden md:block"></div>

             {/* My Designs Button */}
             <button
               onClick={() => setShowSavedList(true)}
               className="flex items-center gap-2 text-sm font-medium text-slate-600 hover:text-brand-600 transition-colors"
             >
               <FolderHeart size={18} />
               <span className="hidden sm:inline">My Designs</span>
             </button>

             <a href="https://github.com" target="_blank" rel="noreferrer" className="text-slate-400 hover:text-slate-800 transition-colors ml-2">
                <span className="text-xs font-semibold border border-slate-200 px-2 py-1 rounded-md">V1.0</span>
             </a>
        </div>
      </header>

      {/* --- Main Content --- */}
      <main className="flex-1 flex flex-col md:flex-row overflow-hidden relative">

        {/* --- Left / Top: Visualizer --- */}
        <div className="flex-1 flex flex-col min-w-0 bg-slate-100 relative">

          {/* Style Carousel (Overlay or Top Bar) */}
          {state.originalImage && (
            <div className="flex-none h-24 bg-white/80 backdrop-blur-md border-b border-white/50 flex items-center px-4 gap-3 overflow-x-auto scrollbar-hide z-10 shadow-sm">
               {DESIGN_STYLES.map((style) => (
                 <button
                    key={style.id}
                    onClick={() => handleGenerate(`Apply ${style.name} interior design style`, style.id)}
                    disabled={state.isGenerating}
                    className={`flex-none group relative rounded-xl overflow-hidden w-40 h-16 transition-all transform hover:scale-105 ${state.activeStyle === style.id ? 'ring-2 ring-brand-500 scale-105' : 'opacity-80 hover:opacity-100'}`}
                 >
                    <img src={style.image} alt={style.name} className="w-full h-full object-cover" />
                    <div className="absolute inset-0 bg-black/40 group-hover:bg-black/70 transition-colors duration-300 flex flex-col items-center justify-center p-2">
                       <span className="text-white text-xs font-bold shadow-sm">{style.name}</span>
                       <span className="text-[10px] text-gray-100 mt-1 text-center leading-tight opacity-0 group-hover:opacity-100 transition-opacity duration-300 hidden group-hover:block line-clamp-2">
                           {style.description}
                       </span>
                    </div>
                    {state.isGenerating && state.activeStyle === style.id && (
                        <div className="absolute inset-0 bg-black/60 flex items-center justify-center">
                            <Loader size="small" />
                        </div>
                    )}
                 </button>
               ))}
            </div>
          )}

          {/* Visualizer Area */}
          <div className="flex-1 relative flex items-center justify-center p-4 md:p-8 overflow-hidden">

             {!state.originalImage ? (
                // Upload State
                <div className="w-full max-w-md bg-white rounded-3xl border-2 border-dashed border-slate-300 p-12 flex flex-col items-center justify-center text-center hover:border-brand-400 transition-colors group cursor-pointer relative">
                    <input 
                      type="file" 
                      accept="image/*" 
                      onChange={handleFileUpload} 
                      className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                    />
                    <div className="w-20 h-20 bg-brand-50 rounded-full flex items-center justify-center mb-6 group-hover:bg-brand-100 transition-colors">
                      <ImageIcon className="text-brand-500" size={32} />
                    </div>
                    <h3 className="text-xl font-bold text-slate-800 mb-2">Upload your room</h3>
                    <p className="text-slate-500 text-sm mb-6">Drag & drop or click to upload a photo of your space to start the transformation.</p>
                    <button className="bg-brand-600 text-white px-6 py-2 rounded-full font-medium shadow-lg shadow-brand-200 group-hover:shadow-brand-300 transition-all flex items-center gap-2">
                        <Upload size={16} /> Upload Photo
                    </button>
                </div>
             ) : (
                // Comparison State
                <div className="relative w-full h-full max-w-5xl bg-white rounded-2xl shadow-2xl overflow-hidden border border-slate-200">
                   {state.isGenerating && (
                     <div className="absolute inset-0 z-30 bg-black/30 backdrop-blur-sm flex flex-col items-center justify-center text-white">
                        <Loader />
                        <p className="mt-4 font-medium animate-pulse">Designing your space...</p>
                     </div>
                   )}

                   {activeImage ? (
                     <ComparisonSlider 
                       beforeImage={state.originalImage} 
                       afterImage={activeImage} 
                     />
                   ) : (
                     <img src={state.originalImage} alt="Original" className="w-full h-full object-contain bg-slate-100" />
                   )}

                   {/* Action Buttons */}
                   {activeImage && (
                     <div className="absolute bottom-6 right-6 z-20 flex items-center gap-3">
                        {/* Save Button */}
                        <button 
                          onClick={handleOpenSaveModal}
                          className="bg-white/90 hover:bg-white text-slate-800 p-3 rounded-full shadow-lg backdrop-blur-sm transition-transform hover:scale-110"
                          title="Save Design"
                        >
                          <Save size={20} />
                        </button>
                        {/* Download Button */}
                        <a 
                          href={activeImage} 
                          download="lumina-design.jpg"
                          className="bg-white/90 hover:bg-white text-slate-800 p-3 rounded-full shadow-lg backdrop-blur-sm transition-transform hover:scale-110"
                          title="Download Design"
                        >
                          <Download size={20} />
                        </a>
                     </div>
                   )}
                </div>
             )}

             {error && (
                 <div className="absolute bottom-4 left-1/2 -translate-x-1/2 bg-red-50 text-red-600 px-4 py-2 rounded-lg shadow-lg border border-red-100 flex items-center gap-2 text-sm z-50">
                    <AlertCircle size={16} /> {error}
                 </div>
             )}

          </div>
        </div>

        {/* --- Right / Bottom: Chat --- */}
        <div className="w-full md:w-[400px] flex-none border-l border-slate-200 h-[40vh] md:h-auto z-20">
            <ChatInterface 
              messages={chatHistory} 
              onSendMessage={handleSendMessage}
              isTyping={isChatTyping}
            />
        </div>
      </main>

      {/* --- Modals --- */}

      {/* Save Design Modal */}
      {showSaveModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm">
          <div className="bg-white rounded-2xl shadow-xl w-full max-w-sm p-6 transform transition-all">
            <h3 className="text-lg font-bold text-slate-800 mb-4">Save Your Design</h3>
            <div className="mb-4">
              <label className="block text-sm font-medium text-slate-600 mb-1">Design Name</label>
              <input 
                type="text" 
                value={designName} 
                onChange={(e) => setDesignName(e.target.value)} 
                className="w-full border border-slate-200 rounded-lg px-3 py-2 focus:ring-2 focus:ring-brand-500 focus:outline-none"
                placeholder="e.g. Dream Living Room"
                autoFocus
              />
            </div>
            <div className="flex items-center justify-end gap-2">
              <button 
                onClick={() => setShowSaveModal(false)}
                className="px-4 py-2 text-slate-600 hover:bg-slate-100 rounded-lg font-medium"
              >
                Cancel
              </button>
              <button 
                onClick={confirmSaveDesign}
                disabled={!designName.trim()}
                className="px-4 py-2 bg-brand-600 hover:bg-brand-700 text-white rounded-lg font-medium disabled:opacity-50"
              >
                Save
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Saved Designs List Modal */}
      {showSavedList && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm">
          <div className="bg-white rounded-2xl shadow-xl w-full max-w-2xl h-[80vh] flex flex-col overflow-hidden">
            <div className="p-4 border-b border-slate-200 flex items-center justify-between">
              <h3 className="text-lg font-bold text-slate-800 flex items-center gap-2">
                <FolderHeart className="text-brand-600" /> My Saved Designs
              </h3>
              <button 
                onClick={() => setShowSavedList(false)}
                className="p-1 text-slate-400 hover:text-slate-600 rounded-full hover:bg-slate-100"
              >
                <X size={20} />
              </button>
            </div>

            <div className="flex-1 overflow-y-auto p-4 bg-slate-50">
              {savedDesigns.length === 0 ? (
                <div className="flex flex-col items-center justify-center h-full text-slate-400">
                  <FolderHeart size={48} className="mb-2 opacity-50" />
                  <p>No saved designs yet.</p>
                </div>
              ) : (
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                  {savedDesigns.map(design => (
                    <div key={design.id} className="bg-white rounded-xl border border-slate-200 shadow-sm hover:shadow-md transition-shadow overflow-hidden flex flex-col">
                      <div className="aspect-[4/3] relative bg-slate-100">
                        <img src={design.generatedImage} alt={design.name} className="w-full h-full object-cover" />
                        <div className="absolute inset-0 bg-gradient-to-t from-black/50 to-transparent opacity-0 hover:opacity-100 transition-opacity flex items-end justify-between p-3">
                           <span className="text-white text-xs font-medium">{design.styleName}</span>
                        </div>
                      </div>
                      <div className="p-3 flex-1 flex flex-col">
                        <div className="flex items-start justify-between mb-2">
                          <div>
                            <h4 className="font-semibold text-slate-800 text-sm">{design.name}</h4>
                            <p className="text-xs text-slate-500">{new Date(design.timestamp).toLocaleDateString()}</p>
                          </div>
                          <button 
                            onClick={() => deleteDesign(design.id)}
                            className="text-slate-400 hover:text-red-500 p-1"
                            title="Delete"
                          >
                            <Trash2 size={14} />
                          </button>
                        </div>
                        <p className="text-xs text-slate-500 line-clamp-2 mb-3 flex-1">{design.prompt}</p>
                        <button 
                           onClick={() => loadDesign(design)}
                           className="w-full py-1.5 bg-brand-50 hover:bg-brand-100 text-brand-700 text-xs font-semibold rounded-lg flex items-center justify-center gap-1 transition-colors"
                        >
                           <ExternalLink size={12} /> Open Design
                        </button>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>
        </div>
      )}

    </div>
  );
};

// Simple Loading Spinner Component
const Loader: React.FC<{ size?: 'small' | 'normal' }> = ({ size = 'normal' }) => (
    <div className={`rounded-full border-2 border-current border-t-transparent animate-spin ${size === 'small' ? 'w-4 h-4' : 'w-10 h-10'}`}></div>
);

export default App;
